import * as React from 'react';
import { X } from 'lucide-react';
import clsx from 'clsx';

interface ModalProps {
  isOpen: boolean;
  onClose: () => void;
  title: string;
  children: React.ReactNode;
  maxWidthClass?: string;
}

export function Modal({ isOpen, onClose, title, children, maxWidthClass = 'max-w-lg' }: ModalProps) {
  React.useEffect(() => {
    if (isOpen) document.body.style.overflow = 'hidden';
    else document.body.style.overflow = 'unset';
    return () => { document.body.style.overflow = 'unset'; };
  }, [isOpen]);

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 sm:p-6 animate-in fade-in duration-300">
      <div 
        className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm transition-opacity" 
        onClick={onClose} 
      />
      <div className={`relative w-full ${maxWidthClass} transform overflow-hidden rounded-[2.5rem] bg-white p-8 shadow-2xl transition-all animate-in zoom-in-95 duration-300`}>
        <div className="flex items-center justify-between mb-8">
          <h3 className="text-2xl font-black tracking-tight text-slate-800">{title}</h3>
          <button 
            onClick={onClose}
            className="p-3 text-slate-400 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all active:scale-95"
          >
            <X className="w-5 h-5" />
          </button>
        </div>
        {children}
      </div>
    </div>
  );
}

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"
import { Slot } from "radix-ui"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "group/button inline-flex shrink-0 items-center justify-center rounded-lg border border-transparent bg-clip-padding text-sm font-medium whitespace-nowrap transition-all outline-none select-none focus-visible:border-ring focus-visible:ring-3 focus-visible:ring-ring/50 active:not-aria-[haspopup]:translate-y-px disabled:pointer-events-none disabled:opacity-50 aria-invalid:border-destructive aria-invalid:ring-3 aria-invalid:ring-destructive/20 dark:aria-invalid:border-destructive/50 dark:aria-invalid:ring-destructive/40 [&_svg]:pointer-events-none [&_svg]:shrink-0 [&_svg:not([class*='size-'])]:size-4",
  {
    variants: {
      variant: {
        default: "bg-primary text-primary-foreground [a]:hover:bg-primary/80",
        outline:
          "border-border bg-background hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:border-input dark:bg-input/30 dark:hover:bg-input/50",
        secondary:
          "bg-secondary text-secondary-foreground hover:bg-secondary/80 aria-expanded:bg-secondary aria-expanded:text-secondary-foreground",
        ghost:
          "hover:bg-muted hover:text-foreground aria-expanded:bg-muted aria-expanded:text-foreground dark:hover:bg-muted/50",
        destructive:
          "bg-destructive/10 text-destructive hover:bg-destructive/20 focus-visible:border-destructive/40 focus-visible:ring-destructive/20 dark:bg-destructive/20 dark:hover:bg-destructive/30 dark:focus-visible:ring-destructive/40",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default:
          "h-8 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-2 has-data-[icon=inline-start]:pl-2",
        xs: "h-6 gap-1 rounded-[min(var(--radius-md),10px)] px-2 text-xs in-data-[slot=button-group]:rounded-lg has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "h-7 gap-1 rounded-[min(var(--radius-md),12px)] px-2.5 text-[0.8rem] in-data-[slot=button-group]:rounded-lg has-data-[icon=inline-end]:pr-1.5 has-data-[icon=inline-start]:pl-1.5 [&_svg:not([class*='size-'])]:size-3.5",
        lg: "h-9 gap-1.5 px-2.5 has-data-[icon=inline-end]:pr-3 has-data-[icon=inline-start]:pl-3",
        icon: "size-8",
        "icon-xs":
          "size-6 rounded-[min(var(--radius-md),10px)] in-data-[slot=button-group]:rounded-lg [&_svg:not([class*='size-'])]:size-3",
        "icon-sm":
          "size-7 rounded-[min(var(--radius-md),12px)] in-data-[slot=button-group]:rounded-lg",
        "icon-lg": "size-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

function Button({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"button"> &
  VariantProps<typeof buttonVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "button"

  return (
    <Comp
      data-slot="button"
      data-variant={variant}
      data-size={size}
      className={cn(buttonVariants({ variant, size, className }))}
      {...props}
    />
  )
}

export { Button, buttonVariants }

import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from '../lib/supabase';
import { type User } from '@supabase/supabase-js';

export interface UserProfile {
  id: string;
  full_name: string;
  email: string;
  role_id: string;
  is_active: boolean;
  role?: Role;
}

export interface Role {
  id: string;
  name: string;
  description: string;
  permissions?: RolePermission[];
}

export interface RolePermission {
  module: string;
  can_read: boolean;
  can_create: boolean;
  can_update: boolean;
  can_delete: boolean;
}

interface AuthContextType {
  user: User | null;
  profile: UserProfile | null;
  loading: boolean;
  can: (module: string, action: 'read' | 'create' | 'update' | 'delete') => boolean;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check active sessions
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      if (session?.user) fetchProfile(session.user.id);
      else setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) fetchProfile(session.user.id);
      else {
        setProfile(null);
        setLoading(false);
      }
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('user_profiles')
        .select('*, role:roles(*, permissions:role_permissions(*))')
        .eq('id', userId)
        .single();

      if (error) throw error;
      setProfile(data as UserProfile);
    } catch (err) {
      console.error('Error fetching profile:', err);
    } finally {
      setLoading(false);
    }
  };

  const signOut = async () => {
    await supabase.auth.signOut();
  };

  const can = (module: string, action: 'read' | 'create' | 'update' | 'delete'): boolean => {
    if (!profile || !profile.role?.permissions) return false;
    // Admins always have access
    if (profile.role.name === 'admin') return true;

    const modPerm = profile.role.permissions.find(p => p.module === module);
    if (!modPerm) return false;

    switch (action) {
      case 'read': return modPerm.can_read;
      case 'create': return modPerm.can_create;
      case 'update': return modPerm.can_update;
      case 'delete': return modPerm.can_delete;
      default: return false;
    }
  };

  return (
    <AuthContext.Provider value={{ user, profile, loading, can, signOut }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Search, 
  ClipboardCheck, 
  CheckCircle2, 
  Clock, 
  Filter,
  ListChecks,
  AlertTriangle,
  Save
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Modal } from '../components/ui/Modal';
import { auditService, type Audit, type ChecklistItem, type AuditFinding } from '../services/audits';
import clsx from 'clsx';

const typeMap = {
  'internal': { label: 'Interna', color: 'bg-blue-100 text-blue-600 border-blue-200' },
  'external': { label: 'Externa', color: 'bg-purple-100 text-purple-600 border-purple-200' },
  'follow_up': { label: 'Seguimiento', color: 'bg-amber-100 text-amber-600 border-amber-200' },
};

const statusMap = {
  'planned': { label: 'Planificada', color: 'bg-slate-100 text-slate-500 border-slate-200' },
  'in_progress': { label: 'En Curso', color: 'bg-blue-100 text-blue-600 border-blue-200' },
  'completed': { label: 'Completada', color: 'bg-green-100 text-green-600 border-green-200' },
  'cancelled': { label: 'Cancelada', color: 'bg-red-50 text-red-400 border-red-100' },
};

const resultColors: Record<string, string> = {
  'conforming': 'bg-green-100 text-green-600 border-green-200',
  'non_conforming': 'bg-red-100 text-red-600 border-red-200',
  'observation': 'bg-amber-100 text-amber-600 border-amber-200',
  'not_applicable': 'bg-slate-50 text-slate-400 border-slate-100',
  'pending': 'bg-white text-slate-400 border-slate-200',
};

const resultLabels: Record<string, string> = {
  'conforming': 'Conforme',
  'non_conforming': 'No Conforme',
  'observation': 'Observación',
  'not_applicable': 'N/A',
  'pending': 'Pendiente',
};

export function Auditorias() {
  const [audits, setAudits] = useState<Audit[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedAudit, setSelectedAudit] = useState<Audit | null>(null);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'info' | 'checklist' | 'findings'>('info');
  const [checklist, setChecklist] = useState<ChecklistItem[]>([]);
  const [findings, setFindings] = useState<AuditFinding[]>([]);

  const [newAudit, setNewAudit] = useState<Partial<Audit>>({
    title: '',
    type: 'internal',
    standard: 'ISO 17025',
    lead_auditor: '',
    planned_date: new Date().toISOString().split('T')[0],
    status: 'planned'
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      const data = await auditService.getAll();
      setAudits(data);
    } catch (error) {
      console.error('Error fetching audits:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchData(); }, []);

  const fetchDetailData = async (id: string) => {
    try {
      const [cl, fd] = await Promise.all([
        auditService.getChecklist(id),
        auditService.getFindings(id),
      ]);
      setChecklist(cl);
      setFindings(fd);
    } catch (error) {
      console.error('Error fetching detail:', error);
    }
  };

  const handleOpenDetail = (audit: Audit) => {
    setSelectedAudit(audit);
    fetchDetailData(audit.id);
    setIsDetailOpen(true);
    setActiveTab('info');
  };

  const stats = useMemo(() => ({
    planned: audits.filter(a => a.status === 'planned').length,
    inProgress: audits.filter(a => a.status === 'in_progress').length,
    findingsOpen: audits.reduce((acc, a) => acc + (a.audit_findings?.length || 0), 0),
    completed: audits.filter(a => a.status === 'completed').length,
  }), [audits]);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await auditService.create(newAudit);
      setIsModalOpen(false);
      setNewAudit({ title: '', type: 'internal', standard: 'ISO 17025', lead_auditor: '', planned_date: new Date().toISOString().split('T')[0], status: 'planned' });
      fetchData();
    } catch (error) {
      console.error('Error creating audit:', error);
    }
  };

  const handleLoadChecklist = async () => {
    if (!selectedAudit) return;
    try {
      await auditService.generateISOChecklist(selectedAudit.id);
      fetchDetailData(selectedAudit.id);
    } catch (error) {
      console.error('Error loading checklist:', error);
    }
  };

  const handleResultChange = async (itemId: string, result: string) => {
    try {
      await auditService.updateChecklistResult(itemId, result);
      fetchDetailData(selectedAudit!.id);
    } catch (error) {
      console.error('Error updating result:', error);
    }
  };

  const handleGenerateFinding = async (item: ChecklistItem) => {
    if (!selectedAudit) return;
    try {
      await auditService.addFinding({
        audit_id: selectedAudit.id,
        checklist_item_id: item.id,
        finding_type: item.result === 'non_conforming' ? 'non_conformity' : 'observation',
        description: `Hallazgo en cláusula ${item.clause}: ${item.requirement}`,
        clause_ref: item.clause,
        severity: item.result === 'non_conforming' ? 'mayor' : 'menor',
      });
      fetchDetailData(selectedAudit.id);
    } catch (error) {
      console.error('Error generating finding:', error);
    }
  };

  const filteredAudits = audits.filter(a =>
    a.title.toLowerCase().includes(search.toLowerCase()) ||
    a.audit_code.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800 uppercase">Auditorías</h1>
          <p className="text-xs font-bold text-slate-400">Planificación, checklists ISO y registro de hallazgos (ISO 19011 / 17025 §8.8).</p>
        </div>
        <div className="flex items-center gap-4">
          <div className="relative w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input
              type="text"
              placeholder="Código o título..."
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-[1.25rem] py-3.5 pl-11 pr-4 text-[11px] font-black outline-none focus:ring-4 focus:ring-primary/5 transition-all shadow-sm"
            />
          </div>
          <Button
            onClick={() => setIsModalOpen(true)}
            className="rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 shadow-xl shadow-primary/20 transition-all hover:scale-[1.03] active:scale-95"
          >
            <Plus className="w-5 h-5 stroke-[3px]" />
            NUEVA AUDITORÍA
          </Button>
        </div>
      </div>

      {/* KPIs */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
          <div className="flex items-center gap-4 mb-3">
            <div className="p-3.5 bg-blue-50 rounded-2xl"><ClipboardCheck className="w-5 h-5 text-blue-500" /></div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Planificadas</span>
          </div>
          <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.planned}</span>
        </Card>
        <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
          <div className="flex items-center gap-4 mb-3">
            <div className="p-3.5 bg-amber-50 rounded-2xl"><Clock className="w-5 h-5 text-amber-500" /></div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">En Curso</span>
          </div>
          <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.inProgress}</span>
        </Card>
        <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
          <div className="flex items-center gap-4 mb-3">
            <div className="p-3.5 bg-red-50 rounded-2xl"><AlertTriangle className="w-5 h-5 text-red-500" /></div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Hallazgos</span>
          </div>
          <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.findingsOpen}</span>
        </Card>
        <Card className="rounded-[2.5rem] border-none bg-slate-900 p-6 shadow-xl shadow-slate-200">
          <div className="flex items-center gap-4 mb-3">
            <div className="p-3.5 bg-white/10 rounded-2xl"><CheckCircle2 className="w-5 h-5 text-green-400" /></div>
            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Completadas</span>
          </div>
          <span className="text-3xl font-black text-white tracking-tighter">{stats.completed}</span>
        </Card>
      </div>

      {/* Table */}
      <Card className="rounded-[2.5rem] border-none shadow-[0_12px_45px_-12px_rgba(0,0,0,0.05)] bg-white overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
          <div className="flex items-center gap-3">
            <ClipboardCheck className="w-5 h-5 text-slate-800" />
            <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest">Programa de Auditorías</h2>
          </div>
          <button className="p-2 text-slate-400 hover:text-slate-800 transition-colors"><Filter className="w-5 h-5" /></button>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/30">
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Código</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Auditoría</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Tipo</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Auditor Líder</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Fecha</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Hallazgos</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 text-right">Estado</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                [1, 2, 3, 4].map(i => (
                  <tr key={i} className="animate-pulse">
                    <td colSpan={7} className="py-8 px-8"><div className="h-4 bg-slate-100 rounded-full w-full" /></td>
                  </tr>
                ))
              ) : filteredAudits.length === 0 ? (
                <tr>
                  <td colSpan={7} className="py-12 text-center text-slate-300">No hay auditorías registradas.</td>
                </tr>
              ) : filteredAudits.map(audit => (
                <tr key={audit.id} onClick={() => handleOpenDetail(audit)} className="hover:bg-slate-50/50 transition-colors group cursor-pointer">
                  <td className="py-6 px-8">
                    <span className="text-[11px] font-black text-slate-800 border-b-2 border-primary/20">{audit.audit_code}</span>
                  </td>
                  <td className="py-6 px-8">
                    <span className="text-sm font-black text-slate-800 group-hover:text-primary transition-colors">{audit.title}</span>
                  </td>
                  <td className="py-6 px-8">
                    <span className={clsx("text-[9px] font-black uppercase tracking-widest px-3 py-1.5 rounded-xl border", typeMap[audit.type as keyof typeof typeMap]?.color)}>
                      {typeMap[audit.type as keyof typeof typeMap]?.label}
                    </span>
                  </td>
                  <td className="py-6 px-8">
                    <span className="text-[11px] font-bold text-slate-500">{audit.lead_auditor}</span>
                  </td>
                  <td className="py-6 px-8">
                    <span className="text-[11px] font-bold text-slate-400">{new Date(audit.planned_date).toLocaleDateString()}</span>
                  </td>
                  <td className="py-6 px-8">
                    <span className="text-xs font-black text-red-500">{audit.audit_findings?.length || 0}</span>
                  </td>
                  <td className="py-6 px-8 text-right">
                    <span className={clsx("text-[9px] font-black uppercase tracking-widest px-3 py-1.5 rounded-xl border", statusMap[audit.status as keyof typeof statusMap]?.color)}>
                      {statusMap[audit.status as keyof typeof statusMap]?.label}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Card>

      {/* Detail Modal */}
      <Modal isOpen={isDetailOpen} onClose={() => setIsDetailOpen(false)} title={`Auditoría: ${selectedAudit?.audit_code || ''}`}>
        {selectedAudit && (
          <div className="space-y-6">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl">
              {(['info', 'checklist', 'findings'] as const).map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={clsx(
                    "flex-1 py-2.5 px-4 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all",
                    activeTab === tab ? "bg-white text-slate-800 shadow-sm" : "text-slate-400 hover:text-slate-600"
                  )}
                >
                  {tab === 'info' ? 'General' : tab === 'checklist' ? 'Checklist ISO' : 'Hallazgos'}
                </button>
              ))}
            </div>

            {/* Info Tab */}
            {activeTab === 'info' && (
              <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 space-y-4">
                  <div>
                    <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Título</p>
                    <p className="text-sm font-bold text-slate-800">{selectedAudit.title}</p>
                  </div>
                  <div className="grid grid-cols-2 gap-6">
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Norma Base</p>
                      <p className="text-xs font-bold text-slate-700">{selectedAudit.standard}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Tipo</p>
                      <span className={clsx("text-[9px] font-black uppercase tracking-widest px-3 py-1 rounded-xl border", typeMap[selectedAudit.type as keyof typeof typeMap]?.color)}>
                        {typeMap[selectedAudit.type as keyof typeof typeMap]?.label}
                      </span>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Auditor Líder</p>
                      <p className="text-xs font-bold text-slate-700">{selectedAudit.lead_auditor}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Área Auditada</p>
                      <p className="text-xs font-bold text-slate-700">{selectedAudit.auditee_area || 'General'}</p>
                    </div>
                  </div>
                </div>
                <div className="bg-blue-50/50 p-6 rounded-[2rem] border border-blue-100/50">
                  <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">Objetivo</p>
                  <p className="text-sm font-bold text-blue-700 italic">"{selectedAudit.objective || 'Verificar conformidad con la norma aplicable.'}"</p>
                </div>
                {selectedAudit.scope && (
                  <div className="bg-purple-50/50 p-6 rounded-[2rem] border border-purple-100/50">
                    <p className="text-[10px] font-black text-purple-500 uppercase tracking-widest mb-2">Alcance</p>
                    <p className="text-sm font-bold text-purple-700">{selectedAudit.scope}</p>
                  </div>
                )}
              </div>
            )}

            {/* Checklist Tab */}
            {activeTab === 'checklist' && (
              <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                    {checklist.length} cláusulas cargadas
                  </p>
                  {checklist.length === 0 && (
                    <Button onClick={handleLoadChecklist} className="h-9 px-4 rounded-xl text-[10px] font-black bg-primary text-white gap-2">
                      <ListChecks className="w-4 h-4" /> CARGAR CHECKLIST ISO 17025
                    </Button>
                  )}
                </div>

                {checklist.length > 0 && (
                  <div className="max-h-[400px] overflow-y-auto space-y-2 pr-1 custom-scrollbar">
                    {checklist.map(item => (
                      <div key={item.id} className="bg-white border border-slate-100 p-4 rounded-2xl hover:shadow-md transition-all group">
                        <div className="flex items-start justify-between gap-3">
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-1">
                              <span className="text-[10px] font-black text-primary bg-primary/5 px-2 py-0.5 rounded-lg">{item.clause}</span>
                            </div>
                            <p className="text-[11px] font-bold text-slate-700 leading-relaxed">{item.requirement}</p>
                          </div>
                          <div className="flex items-center gap-2 flex-shrink-0">
                            <select
                              value={item.result}
                              onChange={(e) => handleResultChange(item.id, e.target.value)}
                              className={clsx("text-[9px] font-black uppercase px-3 py-1.5 rounded-xl border outline-none cursor-pointer", resultColors[item.result])}
                            >
                              {Object.entries(resultLabels).map(([value, label]) => (
                                <option key={value} value={value}>{label}</option>
                              ))}
                            </select>
                            {(item.result === 'non_conforming' || item.result === 'observation') && (
                              <button
                                onClick={() => handleGenerateFinding(item)}
                                title="Generar hallazgo"
                                className="p-1.5 bg-red-50 text-red-500 rounded-lg hover:bg-red-100 transition-colors"
                              >
                                <AlertTriangle className="w-3.5 h-3.5" />
                              </button>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Findings Tab */}
            {activeTab === 'findings' && (
              <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="flex items-center justify-between">
                  <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{findings.length} hallazgos registrados</p>
                </div>
                {findings.length === 0 ? (
                  <p className="text-center py-8 text-[10px] font-bold text-slate-400">No hay hallazgos. Evalúa el checklist para generar hallazgos.</p>
                ) : (
                  <div className="space-y-3">
                    {findings.map(f => (
                      <div key={f.id} className="bg-white border border-slate-100 p-5 rounded-[2rem] hover:shadow-md transition-all">
                        <div className="flex items-start justify-between gap-4">
                          <div className="space-y-1 flex-1">
                            <div className="flex items-center gap-2">
                              <span className={clsx("text-[9px] font-black uppercase tracking-widest px-2 py-1 rounded-lg border",
                                f.finding_type === 'non_conformity' ? 'bg-red-100 text-red-600 border-red-200' :
                                f.finding_type === 'observation' ? 'bg-amber-100 text-amber-600 border-amber-200' :
                                'bg-blue-100 text-blue-600 border-blue-200'
                              )}>
                                {f.finding_type === 'non_conformity' ? 'No Conformidad' : f.finding_type === 'observation' ? 'Observación' : 'Oportunidad'}
                              </span>
                              {f.clause_ref && <span className="text-[10px] font-black text-primary">§{f.clause_ref}</span>}
                            </div>
                            <p className="text-sm font-bold text-slate-800">{f.description}</p>
                          </div>
                          <span className={clsx("text-[9px] font-black uppercase px-2 py-1 rounded-lg border",
                            f.severity === 'critica' ? 'bg-red-100 text-red-600' : f.severity === 'mayor' ? 'bg-orange-100 text-orange-600' : 'bg-blue-100 text-blue-600'
                          )}>
                            {f.severity}
                          </span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </div>
        )}
      </Modal>

      {/* Create Audit Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Planificar Nueva Auditoría">
        <form onSubmit={handleCreate} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Título de la Auditoría</label>
            <input required placeholder="ej: Auditoría Interna SGC Q1 2026" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newAudit.title} onChange={(e) => setNewAudit({ ...newAudit, title: e.target.value })} />
          </div>
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Tipo</label>
              <select className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold outline-none" value={newAudit.type} onChange={(e) => setNewAudit({ ...newAudit, type: e.target.value as any })}>
                <option value="internal">Interna</option>
                <option value="external">Externa</option>
                <option value="follow_up">Seguimiento</option>
              </select>
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Norma Base</label>
              <select className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold outline-none" value={newAudit.standard} onChange={(e) => setNewAudit({ ...newAudit, standard: e.target.value })}>
                <option value="ISO 17025">ISO 17025:2017</option>
                <option value="ISO 9001">ISO 9001:2015</option>
                <option value="ISO 15189">ISO 15189:2022</option>
                <option value="custom">Personalizado</option>
              </select>
            </div>
          </div>
          <div className="grid grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Auditor Líder</label>
              <input required placeholder="Nombre completo" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold outline-none" value={newAudit.lead_auditor} onChange={(e) => setNewAudit({ ...newAudit, lead_auditor: e.target.value })} />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Fecha Planificada</label>
              <input type="date" required className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold outline-none" value={newAudit.planned_date} onChange={(e) => setNewAudit({ ...newAudit, planned_date: e.target.value })} />
            </div>
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Objetivo</label>
            <textarea rows={2} placeholder="Objetivo de la auditoría..." className="w-full bg-slate-50 border-none rounded-3xl py-4 px-6 text-sm font-bold outline-none resize-none" value={newAudit.objective || ''} onChange={(e) => setNewAudit({ ...newAudit, objective: e.target.value })} />
          </div>
          <div className="flex gap-4 pt-4">
            <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="flex-1 h-13 rounded-2xl font-black border-slate-200 uppercase">cancelar</Button>
            <Button type="submit" className="flex-1 h-13 rounded-2xl font-black bg-primary text-white shadow-xl shadow-primary/20 uppercase gap-3">
              <Save className="w-5 h-5" /> planificar auditoría
            </Button>
          </div>
        </form>
      </Modal>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Search, 
  Settings2, 
  Calendar, 
  FileCheck2, 
  Activity, 
  Loader2, 
  CheckCircle2, 
  XCircle, 
  Clock, 
  MoreVertical,
  Filter,
  BarChart4
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Modal } from '../components/ui/Modal';
import { calibrationService, type Calibration } from '../services/calibration';
import { equipmentService, type Equipment } from '../services/equipment';
import { personnelService, type Personnel } from '../services/personnel';
import clsx from 'clsx';

const statusMap = {
  'completed': { label: 'Completado', color: 'bg-green-50 text-green-600 border-green-100', icon: CheckCircle2 },
  'pending': { label: 'Pendiente', color: 'bg-orange-50 text-orange-600 border-orange-100', icon: Clock },
  'cancelled': { label: 'Cancelado', color: 'bg-red-50 text-red-600 border-red-100', icon: XCircle },
};

const resultMap = {
  'pass': { color: 'text-green-500 bg-green-50 border-green-100' },
  'fail': { color: 'text-red-500 bg-red-50 border-red-100' },
  'limited': { color: 'text-orange-500 bg-orange-50 border-orange-100' },
};

export function Calibraciones() {
  const [calibrations, setCalibrations] = useState<Calibration[]>([]);
  const [equipmentList, setEquipmentList] = useState<Equipment[]>([]);
  const [personnelList, setPersonnelList] = useState<Personnel[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newCalibration, setNewCalibration] = useState<Partial<Calibration>>({
    equipment_id: '',
    technician_id: '',
    calibration_date: new Date().toISOString().split('T')[0],
    result: 'pass',
    status: 'completed',
    certificate_no: '',
    uncertainty: '',
    notes: ''
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      const [c, e, p] = await Promise.all([
        calibrationService.getCalibrations(),
        equipmentService.getAll(),
        personnelService.getPersonnel()
      ]);
      setCalibrations(c);
      setEquipmentList(e);
      setPersonnelList(p);
    } catch (error) {
      console.error('Error fetching:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const stats = useMemo(() => {
    return {
      total: calibrations.length,
      completed: calibrations.filter(c => c.status === 'completed').length,
      pending: calibrations.filter(c => c.status === 'pending').length,
      passRate: calibrations.length > 0 
        ? Math.round((calibrations.filter(c => c.result === 'pass').length / calibrations.length) * 100) 
        : 0
    };
  }, [calibrations]);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await calibrationService.createCalibration(newCalibration);
      setIsModalOpen(false);
      setNewCalibration({
         equipment_id: '',
         technician_id: '',
         calibration_date: new Date().toISOString().split('T')[0],
         result: 'pass',
         status: 'completed',
         certificate_no: '',
         uncertainty: '',
         notes: ''
      });
      fetchData();
    } catch (error) {
      console.error('Error creating:', error);
      alert('Error registrando la calibración. Asegúrate de ejecutar el SQL en Supabase.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const filteredCalibrations = calibrations.filter(c => 
     c.certificate_no.toLowerCase().includes(search.toLowerCase()) || 
     c.equipment?.name.toLowerCase().includes(search.toLowerCase()) ||
     c.technician?.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Control de Calibraciones</h1>
          <p className="text-xs font-bold text-slate-400">Trazabilidad metrológica y aseguramiento de la validez de los resultados.</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 shadow-sm" />
            <input 
              type="text" 
              placeholder="Certificado o equipo..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-[1.25rem] py-3.5 pl-11 pr-4 text-[11px] font-black outline-none focus:ring-4 focus:ring-primary/5 transition-all shadow-sm"
            />
          </div>
          <Button 
            onClick={() => setIsModalOpen(true)}
            className="rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 shadow-xl shadow-primary/20 bg-primary border-none transition-all hover:scale-[1.03] active:scale-95 text-white"
          >
            <Plus className="w-5 h-5 stroke-[3px]" />
            NUEVA CALIBRACIÓN
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-blue-50 rounded-2xl">
                  <Activity className="w-5 h-5 text-blue-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Total Ejecutadas</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.total}</span>
               <span className="text-[10px] font-black text-slate-400 tracking-wide leading-none">Registros</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-green-50 rounded-2xl">
                  <FileCheck2 className="w-5 h-5 text-green-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Cumplimiento</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.completed}</span>
               <span className="text-[10px] font-black text-green-500 tracking-wide leading-none">Completadas</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-orange-50 rounded-2xl">
                  <Calendar className="w-5 h-5 text-orange-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Pendientes</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.pending}</span>
               <span className="text-[10px] font-black text-orange-500 tracking-wide leading-none">Para Programar</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-primary/5 rounded-2xl">
                  <BarChart4 className="w-5 h-5 text-primary" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Tasa Passer</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.passRate}%</span>
               <span className="text-[10px] font-black text-slate-400 tracking-wide leading-none">Exitosas</span>
            </div>
         </Card>
      </div>

      <Card className="rounded-[2.5rem] border-none shadow-[0_12px_45px_-12px_rgba(0,0,0,0.05)] bg-white overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
           <div className="flex items-center gap-3">
              <Settings2 className="w-5 h-5 text-slate-800" />
              <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest">Historial de Calibraciones</h2>
           </div>
           <button className="p-2 text-slate-400 hover:text-slate-800 transition-colors">
              <Filter className="w-5 h-5" />
           </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/30">
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Certificado</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Equipo</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Técnico</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Fecha</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Resultado</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 text-right">Estado</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                [1,2,3,4,5].map(i => (
                  <tr key={i} className="animate-pulse">
                    <td colSpan={6} className="py-8 px-8"><div className="h-4 bg-slate-100 rounded-full w-full"></div></td>
                  </tr>
                ))
              ) : filteredCalibrations.length === 0 ? (
                <tr>
                   <td colSpan={6} className="py-12 text-center">
                      <div className="flex flex-col items-center gap-2 opacity-30">
                         <FileCheck2 className="w-12 h-12" />
                         <p className="text-xs font-black uppercase tracking-widest">No hay registros aún</p>
                      </div>
                   </td>
                </tr>
              ) : filteredCalibrations.map((c) => (
                <tr key={c.id} className="hover:bg-slate-50/50 transition-colors group">
                  <td className="py-6 px-8">
                     <span className="text-[11px] font-black text-primary bg-primary/5 px-2.5 py-1.5 rounded-lg border border-primary/10">
                        {c.certificate_no}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <div className="flex flex-col">
                        <span className="text-sm font-black text-slate-800">{c.equipment?.name}</span>
                        <span className="text-[10px] font-bold text-slate-400">{c.equipment?.internal_id}</span>
                     </div>
                  </td>
                  <td className="py-6 px-8">
                    <div className="flex items-center gap-3">
                       <div className="w-8 h-8 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-400">
                          {c.technician?.name.substring(0,2).toUpperCase()}
                       </div>
                       <span className="text-xs font-bold text-slate-600">{c.technician?.name}</span>
                    </div>
                  </td>
                  <td className="py-6 px-8">
                     <div className="flex items-center gap-2 text-[10px] font-black text-slate-600">
                        <Calendar className="w-3.5 h-3.5 text-slate-300" />
                        {new Date(c.calibration_date).toLocaleDateString()}
                     </div>
                  </td>
                  <td className="py-6 px-8">
                     <span className={clsx("text-[9px] font-black uppercase tracking-widest px-2.5 py-1.5 rounded-xl border", resultMap[c.result]?.color)}>
                        {c.result}
                     </span>
                  </td>
                  <td className="py-6 px-8 text-right">
                     <div className="flex items-center justify-end gap-1.5">
                        {(() => {
                          const StatusIcon = statusMap[c.status]?.icon;
                          return (
                            <span className={clsx("inline-flex items-center gap-1.5 px-3 py-1.5 rounded-xl text-[9px] font-black uppercase tracking-widest border", statusMap[c.status]?.color)}>
                               {StatusIcon && <StatusIcon className="w-3.5 h-3.5" />}
                               {statusMap[c.status]?.label}
                            </span>
                          );
                        })()}
                        <button className="p-2 text-slate-300 hover:text-slate-800 transition-colors">
                           <MoreVertical className="w-4 h-4" />
                        </button>
                     </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Card>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Registrar Calibración" maxWidthClass="max-w-4xl">
         <form onSubmit={handleCreate} className="space-y-8">
            <div className="grid grid-cols-2 gap-8">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Equipo a Calibrar</label>
                  <select 
                    required
                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none appearance-none"
                    value={newCalibration.equipment_id}
                    onChange={(e) => setNewCalibration({...newCalibration, equipment_id: e.target.value})}
                  >
                    <option value="">Seleccionar Equipo...</option>
                    {equipmentList.map(e => <option key={e.id} value={e.id}>{e.name} ({e.internal_id})</option>)}
                  </select>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Técnico Responsable</label>
                  <select 
                    required
                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none appearance-none"
                    value={newCalibration.technician_id}
                    onChange={(e) => setNewCalibration({...newCalibration, technician_id: e.target.value})}
                  >
                    <option value="">Seleccionar Técnico...</option>
                    {personnelList.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
                  </select>
               </div>
            </div>

            <div className="grid grid-cols-3 gap-8">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">No. Certificado</label>
                  <input required placeholder="CERT-2024-001" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newCalibration.certificate_no} onChange={(e) => setNewCalibration({...newCalibration, certificate_no: e.target.value})} />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Fecha de Calibración</label>
                  <input type="date" required className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newCalibration.calibration_date} onChange={(e) => setNewCalibration({...newCalibration, calibration_date: e.target.value})} />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Incertidumbre (k=2)</label>
                  <input placeholder="ej: 0.0012 mm" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newCalibration.uncertainty || ''} onChange={(e) => setNewCalibration({...newCalibration, uncertainty: e.target.value})} />
               </div>
            </div>

            <div className="grid grid-cols-2 gap-8">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Resultado Final</label>
                  <div className="flex gap-3">
                    {['pass', 'fail', 'limited'].map((res: any) => (
                      <button
                        key={res}
                        type="button"
                        onClick={() => setNewCalibration({...newCalibration, result: res})}
                        className={clsx(
                          "flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all",
                          newCalibration.result === res 
                            ? "bg-slate-900 text-white border-slate-900 shadow-lg" 
                            : "bg-white text-slate-400 border-slate-100 hover:border-slate-200"
                        )}
                      >
                        {res === 'pass' ? 'Satisfactorio' : res === 'fail' ? 'No Satisfactorio' : 'Limitado'}
                      </button>
                    ))}
                  </div>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Estado del Registro</label>
                  <div className="flex gap-3">
                    {['pending', 'completed'].map((st: any) => (
                      <button
                        key={st}
                        type="button"
                        onClick={() => setNewCalibration({...newCalibration, status: st})}
                        className={clsx(
                          "flex-1 py-3 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest border transition-all",
                          newCalibration.status === st 
                            ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" 
                            : "bg-white text-slate-400 border-slate-100 hover:border-slate-200"
                        )}
                      >
                        {st === 'pending' ? 'Borrador' : 'Finalizar Log'}
                      </button>
                    ))}
                  </div>
               </div>
            </div>

            <div className="flex gap-4 pt-4 border-t border-slate-50">
               <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="flex-1 h-13 rounded-2xl font-black border-slate-200">CANCELAR</Button>
               <Button type="submit" disabled={isSubmitting} className="flex-1 h-13 rounded-2xl font-black bg-primary text-white shadow-xl shadow-primary/20 gap-3">
                 {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                 VALIDAR Y REGISTRAR
               </Button>
            </div>
         </form>
      </Modal>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { 
  Search, 
  Users, 
  CheckCircle2, 
  ShieldCheck, 
  UserPlus, 
  History, 
  Loader2, 
  MoreVertical,
  ChevronRight,
  TrendingUp,
  Award
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { personnelService, type Personnel, type Competency, type PersonnelCompetency } from '../services/personnel';
import { jobPositionsService, type JobPosition, type JobProfile } from '../services/jobPositions';
import { magnitudesService, type Magnitude } from '../services/magnitudes';
import { Modal } from '../components/ui/Modal';
import clsx from 'clsx';

const levelMap = {
  'basic': { label: 'Básico', color: 'text-slate-500 bg-slate-50 border-slate-100', progress: 30 },
  'intermediate': { label: 'Intermedio', color: 'text-blue-500 bg-blue-50 border-blue-100', progress: 65 },
  'expert': { label: 'Experto', color: 'text-primary bg-primary/5 border-primary/10', progress: 100 },
};

export function Competencias() {
  const [personnelList, setPersonnelList] = useState<Personnel[]>([]);
  const [competencies, setCompetencies] = useState<Competency[]>([]);
  const [magnitudes, setMagnitudes] = useState<Magnitude[]>([]);
  const [allPcData, setAllPcData] = useState<PersonnelCompetency[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');

  // Modal states
  const [isPersonnelModalOpen, setIsPersonnelModalOpen] = useState(false);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [selectedPerson, setSelectedPerson] = useState<Personnel | null>(null);
  const [personCompetencies, setPersonCompetencies] = useState<PersonnelCompetency[]>([]);
  const [selectedPersonProfiles, setSelectedPersonProfiles] = useState<JobProfile[]>([]);
  const [jobPositions, setJobPositions] = useState<JobPosition[]>([]);
  const [isSubmitting, setIsSubmitting] = useState(false);

  const [newPerson, setNewPerson] = useState<Partial<Personnel>>({ 
    name: '', role: '', area: '', status: 'active', job_position_id: null
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      const [pData, cData, mData, pcData, jpData] = await Promise.all([
        personnelService.getPersonnel(),
        personnelService.getCompetencies(),
        magnitudesService.getAll(),
        personnelService.getAllPersonnelCompetencies(),
        jobPositionsService.getJobPositions()
      ]);
      setPersonnelList(pData);
      setCompetencies(cData);
      setMagnitudes(mData);
      setAllPcData(pcData);
      setJobPositions(jpData);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const stats = useMemo(() => {
    if (competencies.length === 0) return { avg: 0, authorizedCount: 0, expertCount: 0 };

    // Calculate authorized count (unique people with at least one auth)
    const authorizedPeople = new Set(allPcData.filter(pc => pc.is_authorized).map(pc => pc.personnel_id));

    // Calculate experts (unique people with at least one expert level auth)
    const expertPeople = new Set(allPcData.filter(pc => pc.is_authorized && pc.level === 'expert').map(pc => pc.personnel_id));

    // Average progress across all active personnel
    const percentages = personnelList.map(p => {
       const pAuthCount = allPcData.filter(pc => pc.personnel_id === p.id && pc.is_authorized).length;
       return (pAuthCount / competencies.length) * 100;
    });
    const avg = percentages.length > 0 ? Math.round(percentages.reduce((a, b) => a + b, 0) / percentages.length) : 0;

    return {
      avg,
      authorizedCount: authorizedPeople.size,
      expertCount: expertPeople.size
    };
  }, [allPcData, competencies, personnelList]);

  const handleOpenAuth = async (person: Personnel) => {
    setSelectedPerson(person);
    setLoading(true);
    try {
      const pc = await personnelService.getPersonnelCompetencies(person.id);
      setPersonCompetencies(pc);

      let profiles: JobProfile[] = [];
      if (person.job_position_id) {
        profiles = await jobPositionsService.getJobProfiles(person.job_position_id);
      }
      setSelectedPersonProfiles(profiles);

      setIsAuthModalOpen(true);
    } catch (error) {
      console.error('Error fetching pc:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleAddPerson = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      await personnelService.createPersonnel(newPerson);
      setIsPersonnelModalOpen(false);
      setNewPerson({ name: '', role: '', area: '', status: 'active', job_position_id: null });
      fetchData();
    } catch (error) {
      console.error('Error creating personnel:', error);
      alert('Error registrando al personal.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleToggleAuth = async (competencyId: string, currentStatus: boolean) => {
    if (!selectedPerson) return;
    try {
      await personnelService.updatePersonnelCompetency(selectedPerson.id, competencyId, {
        is_authorized: !currentStatus,
        authorization_date: new Date().toISOString()
      });
      // Refresh pc data
      const pc = await personnelService.getPersonnelCompetencies(selectedPerson.id);
      setPersonCompetencies(pc);
      // Refresh global stats
      fetchData();
    } catch (error) {
      console.error('Error updating auth:', error);
    }
  };

  const filteredPersonnel = personnelList.filter(p => 
    p.name.toLowerCase().includes(search.toLowerCase()) || 
    p.role.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Capa de Competencias (ISO 17025)</h1>
          <p className="text-xs font-bold text-slate-400">Demuestra que el personal es competente, capacitado y autorizado para tareas específicas.</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 shadow-sm" />
            <input 
              type="text" 
              placeholder="Buscar personal..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-[1.25rem] py-3.5 pl-11 pr-4 text-[11px] font-black outline-none focus:ring-4 focus:ring-primary/5 transition-all shadow-sm"
            />
          </div>
          <Button 
            onClick={() => setIsPersonnelModalOpen(true)}
            className="rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 shadow-xl shadow-primary/20 bg-primary border-none transition-all hover:scale-[1.03] active:scale-95 text-white"
          >
            <UserPlus className="w-5 h-5 stroke-[3px]" />
            REGISTRAR PERSONAL
          </Button>
        </div>
      </div>

      {/* Analytics Brief */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-blue-50 rounded-2xl">
                  <TrendingUp className="w-5 h-5 text-blue-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Promedio Competencia</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.avg}%</span>
               <span className="text-[10px] font-black text-green-500 tracking-wide leading-none">Real</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-green-50 rounded-2xl">
                  <ShieldCheck className="w-5 h-5 text-green-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Autorizados</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.authorizedCount}</span>
               <span className="text-[10px] font-black text-slate-400 tracking-wide leading-none">Personas</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-orange-50 rounded-2xl">
                  <History className="w-5 h-5 text-orange-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Vencimientos Próximos</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">0</span>
               <span className="text-[10px] font-black text-orange-500 tracking-wide leading-none">en 30 días</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-primary/5 rounded-2xl">
                  <Award className="w-5 h-5 text-primary" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Expertos</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.expertCount}</span>
               <span className="text-[10px] font-black text-slate-400 tracking-wide leading-none">Sénior</span>
            </div>
         </Card>
      </div>

      {/* Main Grid: Personnel Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
        {loading && personnelList.length === 0 ? (
          [1,2,3,4,5,6].map(i => <div key={i} className="h-48 bg-slate-100/50 rounded-[3rem] animate-pulse" />)
        ) : filteredPersonnel.map((person: Personnel) => {
          const authCount = allPcData.filter(pc => pc.personnel_id === person.id && pc.is_authorized).length;
          const percentage = competencies.length > 0 ? Math.round((authCount / competencies.length) * 100) : 0;

          return (
            <Card key={person.id} className="border-none shadow-[0_12px_45px_-12px_rgba(0,0,0,0.05)] rounded-[3rem] bg-white group hover:scale-[1.02] hover:shadow-[0_45px_100px_-20px_rgba(0,0,0,0.08)] transition-all duration-500 overflow-hidden border border-white hover:border-slate-100 flex flex-col p-8">
              <div className="flex justify-between items-start mb-6">
                 <div className="flex items-center gap-4">
                    <div className="w-14 h-14 bg-slate-50 border border-slate-100 rounded-2xl flex items-center justify-center text-slate-300 transition-colors group-hover:bg-primary group-hover:text-white">
                       <Users className="w-7 h-7" />
                    </div>
                    <div className="flex flex-col">
                       <h3 className="text-lg font-black text-slate-800 group-hover:text-primary transition-colors leading-tight">{person.name}</h3>
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none mt-1">{person.role}</span>
                    </div>
                 </div>
                 <button className="p-2.5 text-slate-300 hover:text-slate-800 hover:bg-slate-50 rounded-xl active:scale-90 transition-all">
                    <MoreVertical className="w-5 h-5" />
                 </button>
              </div>

              <div className="flex-1 space-y-4 mb-8">
                 <div className="flex flex-col gap-1.5 bg-slate-50 p-4 rounded-2xl border border-slate-100 group-hover:bg-white group-hover:shadow-sm transition-all duration-500">
                    <div className="flex items-center justify-between mb-1">
                       <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">Capacitación</span>
                       <span className="text-[10px] font-black text-primary">{percentage}%</span>
                    </div>
                    <div className="w-full h-1.5 bg-slate-200 rounded-full overflow-hidden">
                       <div className="h-full bg-primary transition-all duration-700" style={{ width: `${percentage}%` }}></div>
                    </div>
                 </div>
              </div>

              <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                 <div className="flex items-center gap-2">
                   {person.status === 'active' ? (
                     <span className="flex items-center gap-1.5 text-[9px] font-black text-green-500 uppercase tracking-widest bg-green-50 px-3 py-1.5 rounded-xl border border-green-100">
                        <CheckCircle2 className="w-3.5 h-3.5" />
                        Activo
                     </span>
                   ) : (
                     <span className="flex items-center gap-1.5 text-[9px] font-black text-slate-400 uppercase tracking-widest bg-slate-50 px-3 py-1.5 rounded-xl">
                        Inactivo
                     </span>
                   )}
                 </div>
                 <button 
                   onClick={() => handleOpenAuth(person)}
                   className="flex items-center gap-2 text-[10px] font-black text-primary hover:gap-4 transition-all hover:text-slate-800 group/btn"
                 >
                   MATRIZ TÉCNICA 
                   <div className="p-1.5 bg-primary/5 rounded-lg group-hover/btn:bg-primary/10">
                     <ChevronRight className="w-4 h-4" />
                  </div>
                 </button>
              </div>
            </Card>
          );
        })}
      </div>

      {/* MODAL: REGISTRAR PERSONAL */}
      <Modal isOpen={isPersonnelModalOpen} onClose={() => setIsPersonnelModalOpen(false)} title="Nuevo Técnico / Personal">
        <form onSubmit={handleAddPerson} className="space-y-6">
           <div className="space-y-2">
             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Nombre Completo</label>
             <input required placeholder="ej: Ing. Ricardo Pérez" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newPerson.name} onChange={(e) => setNewPerson({ ...newPerson, name: e.target.value })} />
           </div>
           <div className="grid grid-cols-1 gap-6">
             <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Cargo Técnico</label>
               <select 
                 required
                 className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none appearance-none" 
                 value={newPerson.job_position_id || ''} 
                 onChange={(e) => {
                   const pos = jobPositions.find(p => p.id === e.target.value);
                   setNewPerson({ 
                     ...newPerson, 
                     job_position_id: pos?.id || null,
                     role: pos?.name || '',
                     area: pos?.department || ''
                   });
                 }}
               >
                 <option value="" disabled>-- Seleccionar Cargo --</option>
                 {jobPositions.map(pos => (
                   <option key={pos.id} value={pos.id}>{pos.name} ({pos.department})</option>
                 ))}
               </select>
             </div>
           </div>
           <div className="flex gap-4 pt-4">
              <Button type="button" variant="outline" onClick={() => setIsPersonnelModalOpen(false)} className="flex-1 h-13 rounded-2xl font-black border-slate-200">CANCELAR</Button>
              <Button type="submit" disabled={isSubmitting} className="flex-1 h-13 rounded-2xl font-black bg-primary text-white shadow-xl shadow-primary/20 gap-3">
                {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                GUARDAR REGISTRO
              </Button>
           </div>
        </form>
      </Modal>

      {/* MODAL: MATRIZ DE AUTORIZACIÓN (ISO 17025) */}
      <Modal isOpen={isAuthModalOpen} onClose={() => setIsAuthModalOpen(false)} title={`Matriz Técnica: ${selectedPerson?.name}`} maxWidthClass="max-w-4xl">
         <div className="space-y-8 max-h-[70vh] overflow-y-auto pr-4 custom-scrollbar">
            <p className="text-xs font-bold text-slate-400 leading-relaxed bg-slate-50 p-4 rounded-2xl border border-slate-100">
               <ShieldCheck className="w-4 h-4 inline-block mr-2 text-primary" />
               Define las autorizaciones específicas para cada magnitud metrológica.
            </p>

            <div className="space-y-4">
               {competencies.length === 0 ? (
                 <p className="text-center py-8 text-xs font-black text-slate-300 uppercase tracking-widest leading-loose">No hay competencias definidas en el catálogo <br/> vinculadas a magnitudes.</p>
               ) : competencies.map((comp: any) => {
                 const pc = personCompetencies.find(x => x.competency_id === comp.id);
                 const levelInfo = pc ? (levelMap[pc.level as keyof typeof levelMap] || levelMap.basic) : levelMap.basic;

                 const profile = selectedPersonProfiles.find(p => p.competency_id === comp.id);
                 const hasBrecha = profile && profile.is_mandatory && (!pc || !pc.is_authorized);

                 return (
                   <Card key={comp.id} className={clsx("p-6 rounded-[2rem] border transition-all shadow-sm", hasBrecha ? "border-red-100 bg-red-50/20" : "border-slate-50 bg-white hover:border-slate-100")}>
                      <div className="flex items-center justify-between gap-6">
                         <div className="flex items-center gap-5 flex-1">
                            <div className="w-14 h-14 bg-slate-50 rounded-2xl flex flex-col items-center justify-center border border-slate-100">
                               <span className="text-[8px] font-black text-slate-300 uppercase leading-none mb-1">Magnitud</span>
                               <span className="text-[11px] font-black text-slate-800 leading-none">{comp.magnitude?.name || 'GEN'}</span>
                            </div>
                            <div className="flex flex-col">
                               <h4 className="text-sm font-black text-slate-800 flex items-center gap-2">
                                 {comp.name}
                                 {hasBrecha && <span className="px-2 py-0.5 rounded bg-red-100 text-red-600 text-[9px] font-black uppercase tracking-widest">Brecha</span>}
                               </h4>
                               <p className="text-[10px] font-bold text-slate-400 line-clamp-1">{comp.description || 'Sin descripción técnica'}</p>
                            </div>
                         </div>

                         <div className="flex items-center gap-8">
                            {/* Level Visualizer */}
                            <div className="flex flex-col items-end gap-1.5 w-32">
                               <span className={clsx("text-[9px] font-black uppercase tracking-widest leading-none px-2 py-1 rounded-lg", levelInfo.color)}>
                                 {levelInfo.label}
                               </span>
                               <div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden">
                                  <div className="h-full bg-primary transition-all duration-700" style={{ width: `${levelInfo.progress}%` }}></div>
                               </div>
                            </div>

                            {/* Toggle Auth */}
                            <div className="flex items-center gap-3">
                               <div className="h-8 w-px bg-slate-100" />
                               <Button 
                                 onClick={() => handleToggleAuth(comp.id, pc?.is_authorized || false)}
                                 variant={pc?.is_authorized ? "default" : "outline"}
                                 className={clsx(
                                   "rounded-xl h-10 px-4 font-black text-[10px] tracking-widest gap-2 transition-all active:scale-95",
                                   pc?.is_authorized ? "bg-green-500 hover:bg-green-600 text-white shadow-lg shadow-green-200" : "border-slate-100 text-slate-400"
                                 )}
                               >
                                 {pc?.is_authorized ? <ShieldCheck className="w-4 h-4" /> : <ShieldCheck className="w-4 h-4 opacity-30" />}
                                 {pc?.is_authorized ? 'AUTORIZADO' : 'NO AUTORIZADO'}
                               </Button>
                            </div>
                         </div>
                      </div>
                   </Card>
                 );
               })}
            </div>

            {/* SEED FOR DEMO if empty competencies */}
            {competencies.length === 0 && (
              <div className="flex justify-center pt-4">
                 <Button 
                   variant="outline" 
                   onClick={async () => {
                     const seed = magnitudes.map(m => ({
                       name: `Calibración de ${m.name}`,
                       description: `Habilidad para ejecutar el método de calibración en la magnitud ${m.name}.`,
                       magnitude_id: m.id
                     }));
                     for (const c of seed) {
                       await personnelService.createCompetency(c);
                     }
                     fetchData();
                   }}
                   className="rounded-xl font-bold border-slate-200 uppercase text-[9px] tracking-widest"
                 >
                   AUTOGENERAR COMPETENCIAS BASE
                 </Button>
              </div>
            )}

            <div className="pt-8 border-t border-slate-50">
               <Button onClick={() => setIsAuthModalOpen(false)} className="w-full h-13 rounded-2xl font-black bg-slate-900 border-none shadow-xl shadow-slate-200 text-white tracking-widest text-[10px]">
                  CERRAR MATRIZ TÉCNICA
               </Button>
            </div>
         </div>
      </Modal>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { 
  Building2, 
  Settings2, 
  GraduationCap, 
  Plus, 
  Edit2, 
  Trash2, 
  Save, 
  Loader2,
  FileCheck2,
  AlertTriangle
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Modal } from '../components/ui/Modal';
import { PermissionGuard } from '../components/PermissionGuard';
import { jobPositionsService, type JobPosition, type JobProfile, type EducationRequirement } from '../services/jobPositions';
import { personnelService, type Competency } from '../services/personnel';
import clsx from 'clsx';

export function ConfiguracionCargos() {
  const [activeTab, setActiveTab] = useState<'positions' | 'profiles' | 'education'>('positions');
  const [positions, setPositions] = useState<JobPosition[]>([]);
  const [competencies, setCompetencies] = useState<Competency[]>([]);
  const [selectedPosition, setSelectedPosition] = useState<JobPosition | null>(null);

  const [profiles, setProfiles] = useState<JobProfile[]>([]);
  const [educationReqs, setEducationReqs] = useState<EducationRequirement[]>([]);

  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);

  // Position Modal
  const [isPositionModalOpen, setIsPositionModalOpen] = useState(false);
  const [editingPosition, setEditingPosition] = useState<JobPosition | null>(null);
  const [newPosition, setNewPosition] = useState<Partial<JobPosition>>({ name: '', department: '', description: '', is_active: true });

  // Add Req Modal
  const [isEducationModalOpen, setIsEducationModalOpen] = useState(false);
  const [newEducationReq, setNewEducationReq] = useState<Partial<EducationRequirement>>({ req_type: 'degree', description: '', is_mandatory: true });

  const fetchData = async () => {
    try {
      setLoading(true);
      const [posData, compData] = await Promise.all([
        jobPositionsService.getJobPositions(),
        personnelService.getCompetencies()
      ]);
      setPositions(posData);
      setCompetencies(compData);
      if (posData.length > 0 && !selectedPosition) {
        setSelectedPosition(posData[0]);
      }
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchPositionDetails = async (positionId: string) => {
    try {
      const [profData, eduData] = await Promise.all([
        jobPositionsService.getJobProfiles(positionId),
        jobPositionsService.getEducationRequirements(positionId)
      ]);
      setProfiles(profData);
      setEducationReqs(eduData);
    } catch (error) {
      console.error('Error fetching position details:', error);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  useEffect(() => {
    if (selectedPosition) {
      fetchPositionDetails(selectedPosition.id);
    }
  }, [selectedPosition]);

  const handleSavePosition = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      if (editingPosition) {
        await jobPositionsService.updateJobPosition(editingPosition.id, newPosition);
      } else {
        const added = await jobPositionsService.createJobPosition(newPosition);
        setSelectedPosition(added);
      }
      setIsPositionModalOpen(false);
      fetchData();
    } catch (error) {
      console.error('Error saving position:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleSaveProfileLevel = async (competencyId: string, level: 'basic' | 'intermediate' | 'expert', mandatory: boolean) => {
    if (!selectedPosition) return;
    try {
      await jobPositionsService.saveJobProfile({
        job_position_id: selectedPosition.id,
        competency_id: competencyId,
        required_level: level,
        is_mandatory: mandatory
      });
      fetchPositionDetails(selectedPosition.id);
    } catch (error) {
      console.error('Error saving profile level:', error);
    }
  };

  const handleSelectCompetencyLevel = (competencyId: string, value: string) => {
    if (!value) {
      // Find and delete if exists
      const existing = profiles.find(p => p.competency_id === competencyId);
      if (existing) {
        jobPositionsService.deleteJobProfile(existing.id).then(() => {
          fetchPositionDetails(selectedPosition!.id);
        });
      }
    } else {
      const [level, mandatoryStr] = value.split('-');
      handleSaveProfileLevel(competencyId, level as any, mandatoryStr === 'true');
    }
  };

  const handleSaveEducation = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedPosition) return;
    setIsSubmitting(true);
    try {
      await jobPositionsService.createEducationRequirement({
        ...newEducationReq,
        job_position_id: selectedPosition.id
      });
      setIsEducationModalOpen(false);
      setNewEducationReq({ req_type: 'degree', description: '', is_mandatory: true });
      fetchPositionDetails(selectedPosition.id);
    } catch (error) {
      console.error('Error saving education req:', error);
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDeleteEducation = async (id: string) => {
    try {
      await jobPositionsService.deleteEducationRequirement(id);
      fetchPositionDetails(selectedPosition!.id);
    } catch (error) {
      console.error('Error deleting education req:', error);
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Cargos y Perfiles</h1>
          <p className="text-sm font-bold text-slate-400 mt-1">
            Configuración de requisitos y competencias base por cargo (ISO 17025 Cláusula 6.2)
          </p>
        </div>
      </div>

      <div className="flex gap-4 border-b border-slate-200">
        {[
          { id: 'positions', label: 'Cargos del Laboratorio', icon: Building2 },
          { id: 'profiles', label: 'Perfiles de Competencia', icon: Settings2 },
          { id: 'education', label: 'Requisitos Educativos', icon: GraduationCap }
        ].map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id as any)}
            className={clsx(
              "flex items-center gap-2 px-6 py-4 font-bold text-sm border-b-2 transition-all",
              activeTab === tab.id 
                ? "border-primary text-primary" 
                : "border-transparent text-slate-400 hover:text-slate-600 hover:border-slate-300"
            )}
          >
            <tab.icon className="w-4 h-4" />
            {tab.label}
          </button>
        ))}
      </div>

      {loading ? (
        <div className="flex items-center justify-center p-12">
          <Loader2 className="w-8 h-8 text-primary animate-spin" />
        </div>
      ) : (
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
          {/* Sidebar for selecting position (visible in profiles and education tabs) */}
          {(activeTab === 'profiles' || activeTab === 'education') && (
            <div className="lg:col-span-1 space-y-4">
              <h3 className="text-xs font-black text-slate-400 uppercase tracking-widest pl-2">Seleccionar Cargo</h3>
              <div className="space-y-2">
                {positions.map(pos => (
                  <button
                    key={pos.id}
                    onClick={() => setSelectedPosition(pos)}
                    className={clsx(
                      "w-full text-left px-4 py-3 rounded-2xl text-sm font-bold transition-all border",
                      selectedPosition?.id === pos.id 
                        ? "bg-primary text-white border-primary shadow-lg shadow-primary/20" 
                        : "bg-white text-slate-600 border-slate-100 hover:border-primary/30"
                    )}
                  >
                    <div className="block truncate">{pos.name}</div>
                    <div className={clsx("text-[10px] mt-1 uppercase tracking-widest", selectedPosition?.id === pos.id ? "text-primary-foreground/70" : "text-slate-400")}>
                      {pos.department}
                    </div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {/* Main Content Area */}
          <div className={activeTab === 'positions' ? "lg:col-span-4" : "lg:col-span-3"}>

            {/* CARGOS TAB */}
            {activeTab === 'positions' && (
              <div className="space-y-6">
                <div className="flex justify-end">
                  <PermissionGuard module="config_cargos" action="create">
                    <Button 
                      onClick={() => {
                        setEditingPosition(null);
                        setNewPosition({ name: '', department: '', description: '', is_active: true });
                        setIsPositionModalOpen(true);
                      }}
                      className="rounded-[1.25rem] h-12 px-6 font-black bg-primary text-white"
                    >
                      <Plus className="w-4 h-4 mr-2" />
                      AÑADIR CARGO
                    </Button>
                  </PermissionGuard>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
                  {positions.map(pos => (
                    <Card key={pos.id} className="border-none shadow-sm rounded-[2rem] bg-white overflow-hidden p-6 hover:shadow-md transition-shadow">
                      <div className="flex justify-between items-start mb-4">
                        <div className="w-12 h-12 rounded-2xl bg-blue-50 text-blue-600 flex items-center justify-center">
                          <Building2 className="w-6 h-6" />
                        </div>
                        <PermissionGuard module="config_cargos" action="update">
                          <button 
                            onClick={() => {
                              setEditingPosition(pos);
                              setNewPosition(pos);
                              setIsPositionModalOpen(true);
                            }}
                            className="p-2 text-slate-400 hover:text-primary transition-colors"
                          >
                            <Edit2 className="w-4 h-4" />
                          </button>
                        </PermissionGuard>
                      </div>
                      <h3 className="text-xl font-black text-slate-800 mb-1 leading-tight">{pos.name}</h3>
                      <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-4">{pos.department}</p>
                      <p className="text-sm font-medium text-slate-500 line-clamp-3 mb-6">{pos.description}</p>
                      <div className="flex items-center gap-2">
                        <span className={clsx("px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest", pos.is_active ? "bg-green-50 text-green-600" : "bg-red-50 text-red-600")}>
                          {pos.is_active ? 'Activo' : 'Inactivo'}
                        </span>
                      </div>
                    </Card>
                  ))}
                  {positions.length === 0 && (
                    <div className="col-span-full p-12 text-center text-slate-400 font-bold bg-slate-50 rounded-[2rem] border-2 border-dashed border-slate-200">
                      No hay cargos configurados.
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* PERFILES TAB */}
            {activeTab === 'profiles' && selectedPosition && (
              <Card className="border-none shadow-sm rounded-[2rem] bg-white overflow-hidden">
                <div className="p-6 border-b border-slate-100 bg-slate-50/50 flex items-center gap-4">
                  <div className="w-12 h-12 rounded-2xl bg-white shadow-sm flex items-center justify-center text-primary">
                    <Settings2 className="w-6 h-6" />
                  </div>
                  <div>
                    <h2 className="text-xl font-black text-slate-800">Matriz de Competencias Requeridas</h2>
                    <p className="text-sm font-bold text-slate-400">Perfil: <span className="text-primary">{selectedPosition.name}</span></p>
                  </div>
                </div>
                <div className="p-6 space-y-6">
                  {competencies.length === 0 ? (
                    <p className="text-center text-slate-400 py-8">No hay competencias definidas en el sistema.</p>
                  ) : (
                    <div className="border border-slate-100 rounded-3xl overflow-hidden">
                      <table className="w-full text-left border-collapse">
                        <thead>
                          <tr className="bg-slate-50 border-b border-slate-100">
                            <th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Competencia</th>
                            <th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nivel Requerido</th>
                            <th className="p-4 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado</th>
                          </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-50">
                          {competencies.map(comp => {
                            const profile = profiles.find(p => p.competency_id === comp.id);
                            // value format: "level-isMandatory" or ""
                            let selectValue = "";
                            if (profile) {
                              selectValue = `${profile.required_level}-${profile.is_mandatory}`;
                            }

                            return (
                              <tr key={comp.id} className="hover:bg-slate-50/50 transition-colors">
                                <td className="p-4">
                                  <div className="font-bold text-slate-800 text-sm">{comp.name}</div>
                                  <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">
                                    {comp.magnitude?.name || 'General'}
                                  </div>
                                </td>
                                <td className="p-4">
                                  <select 
                                    className={clsx(
                                      "bg-slate-50 border-none rounded-xl py-2 px-4 text-xs font-bold outline-none ring-2 ring-transparent focus:ring-primary/20 transition-all",
                                      profile ? "bg-primary/5 text-primary" : "text-slate-400"
                                    )}
                                    value={selectValue}
                                    onChange={(e) => handleSelectCompetencyLevel(comp.id, e.target.value)}
                                  >
                                    <option value="">-- No Requerida --</option>
                                    <optgroup label="Obligatoria (Nivel Mínimo)">
                                      <option value="basic-true">Básico Obligatorio</option>
                                      <option value="intermediate-true">Intermedio Obligatorio</option>
                                      <option value="expert-true">Experto Obligatorio</option>
                                    </optgroup>
                                    <optgroup label="Deseable (Opcional)">
                                      <option value="basic-false">Básico Deseable</option>
                                      <option value="intermediate-false">Intermedio Deseable</option>
                                      <option value="expert-false">Experto Deseable</option>
                                    </optgroup>
                                  </select>
                                </td>
                                <td className="p-4">
                                  {profile ? (
                                    <div className="flex items-center gap-2">
                                      <CheckCircle2 className="w-4 h-4 text-green-500" />
                                      <span className="text-xs font-bold text-green-600">Configurado</span>
                                    </div>
                                  ) : (
                                    <span className="text-xs font-bold text-slate-400">-</span>
                                  )}
                                </td>
                              </tr>
                            );
                          })}
                        </tbody>
                      </table>
                    </div>
                  )}
                </div>
              </Card>
            )}

            {/* EDUCATION TAB */}
            {activeTab === 'education' && selectedPosition && (
              <div className="space-y-6">
                <div className="flex justify-between items-center bg-white p-6 rounded-[2rem] shadow-sm">
                  <div>
                    <h2 className="text-xl font-black text-slate-800">Formación y Experiencia Requerida</h2>
                    <p className="text-sm font-bold text-slate-400">Perfil: <span className="text-primary">{selectedPosition.name}</span></p>
                  </div>
                  <PermissionGuard module="config_cargos" action="create">
                    <Button 
                      onClick={() => setIsEducationModalOpen(true)}
                      className="rounded-[1rem] h-10 px-4 font-black bg-slate-100 text-slate-600 hover:bg-slate-200"
                    >
                      <Plus className="w-4 h-4 mr-2" />
                      AÑADIR REQUISITO
                    </Button>
                  </PermissionGuard>
                </div>

                <div className="grid grid-cols-1 gap-4">
                  {educationReqs.map(req => (
                    <Card key={req.id} className="border-none shadow-sm rounded-2xl bg-white p-5 flex items-center justify-between border-l-4 border-l-primary">
                      <div className="flex items-center gap-4">
                        <div className="w-10 h-10 rounded-xl bg-slate-50 flex items-center justify-center text-slate-400">
                          {req.req_type === 'degree' && <GraduationCap className="w-5 h-5" />}
                          {req.req_type === 'course' && <FileCheck2 className="w-5 h-5" />}
                          {req.req_type === 'experience' && <Building2 className="w-5 h-5" />}
                          {req.req_type === 'other' && <AlertTriangle className="w-5 h-5" />}
                        </div>
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">
                              {req.req_type === 'degree' ? 'Educación Formal' : req.req_type === 'course' ? 'Formación Especifica' : req.req_type === 'experience' ? 'Experiencia Mínima' : 'Otro Requisito'}
                            </span>
                            {req.is_mandatory ? (
                              <span className="px-2 py-0.5 rounded-md bg-red-50 text-red-500 text-[9px] font-bold uppercase tracking-wider">Obligatorio</span>
                            ) : (
                              <span className="px-2 py-0.5 rounded-md bg-blue-50 text-blue-500 text-[9px] font-bold uppercase tracking-wider">Deseable</span>
                            )}
                          </div>
                          <p className="text-sm font-bold text-slate-700">{req.description}</p>
                        </div>
                      </div>
                      <PermissionGuard module="config_cargos" action="delete">
                        <button onClick={() => handleDeleteEducation(req.id)} className="p-2 text-slate-300 hover:text-red-500 transition-colors">
                          <Trash2 className="w-4 h-4" />
                        </button>
                      </PermissionGuard>
                    </Card>
                  ))}
                  {educationReqs.length === 0 && (
                    <div className="p-8 text-center bg-white rounded-2xl border border-dashed border-slate-200 text-slate-400 font-bold text-sm">
                      No se han configurado requisitos de formación para este cargo.
                    </div>
                  )}
                </div>
              </div>
            )}

          </div>
        </div>
      )}

      {/* Position Modal */}
      <Modal isOpen={isPositionModalOpen} onClose={() => setIsPositionModalOpen(false)} title={editingPosition ? "Editar Cargo" : "Nuevo Cargo"}>
        <form onSubmit={handleSavePosition} className="space-y-4">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Nombre del Cargo</label>
            <input required className="w-full bg-slate-50 border-none rounded-2xl py-3 px-4 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20" value={newPosition.name || ''} onChange={(e) => setNewPosition({...newPosition, name: e.target.value})} placeholder="Ej: Director Técnico" />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Área / Departamento</label>
            <input required className="w-full bg-slate-50 border-none rounded-2xl py-3 px-4 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20" value={newPosition.department || ''} onChange={(e) => setNewPosition({...newPosition, department: e.target.value})} placeholder="Ej: Laboratorio" />
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Descripción</label>
            <textarea className="w-full bg-slate-50 border-none rounded-2xl py-3 px-4 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20 h-24 resize-none" value={newPosition.description || ''} onChange={(e) => setNewPosition({...newPosition, description: e.target.value})} placeholder="Responsabilidades principales..." />
          </div>
          <div className="flex items-center gap-3 pt-2">
            <input type="checkbox" id="isActive" className="w-4 h-4 rounded text-primary border-slate-300 focus:ring-primary/20" checked={newPosition.is_active || false} onChange={(e) => setNewPosition({...newPosition, is_active: e.target.checked})} />
            <label htmlFor="isActive" className="text-sm font-bold text-slate-600 cursor-pointer">Cargo Activo</label>
          </div>
          <div className="pt-4 flex gap-3">
            <Button type="button" variant="outline" onClick={() => setIsPositionModalOpen(false)} className="flex-1 rounded-2xl font-black">CANCELAR</Button>
            <Button type="submit" disabled={isSubmitting} className="flex-1 rounded-2xl font-black bg-primary text-white">
              {isSubmitting ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4 mr-2" />}
              GUARDAR
            </Button>
          </div>
        </form>
      </Modal>

      {/* Education Req Modal */}
      <Modal isOpen={isEducationModalOpen} onClose={() => setIsEducationModalOpen(false)} title="Añadir Requisito Educativo">
        <form onSubmit={handleSaveEducation} className="space-y-4">
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Tipo de Requisito</label>
            <select required className="w-full bg-slate-50 border-none rounded-2xl py-3 px-4 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20" value={newEducationReq.req_type} onChange={(e) => setNewEducationReq({...newEducationReq, req_type: e.target.value as any})}>
              <option value="degree">Educación Formal (Título)</option>
              <option value="course">Formación / Cursos</option>
              <option value="experience">Experiencia Profesional</option>
              <option value="other">Otro Requisito</option>
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Descripción del Requisito</label>
            <textarea required className="w-full bg-slate-50 border-none rounded-2xl py-3 px-4 text-sm font-bold outline-none focus:ring-2 focus:ring-primary/20 h-24 resize-none" value={newEducationReq.description || ''} onChange={(e) => setNewEducationReq({...newEducationReq, description: e.target.value})} placeholder="Ej: Ingeniero Electrónico o afín..." />
          </div>
          <div className="flex items-center gap-3 pt-2">
            <input type="checkbox" id="isMandatory" className="w-4 h-4 rounded text-primary border-slate-300 focus:ring-primary/20" checked={newEducationReq.is_mandatory || false} onChange={(e) => setNewEducationReq({...newEducationReq, is_mandatory: e.target.checked})} />
            <label htmlFor="isMandatory" className="text-sm font-bold text-slate-600 cursor-pointer">Requisito Obligatorio (Esencial)</label>
          </div>
          <div className="pt-4 flex gap-3">
            <Button type="button" variant="outline" onClick={() => setIsEducationModalOpen(false)} className="flex-1 rounded-2xl font-black">CANCELAR</Button>
            <Button type="submit" disabled={isSubmitting} className="flex-1 rounded-2xl font-black bg-primary text-white">
              <Plus className="w-4 h-4 mr-2" />
              AÑADIR
            </Button>
          </div>
        </form>
      </Modal>

    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Search, 
  FileText, 
  Files, 
  ShieldCheck, 
  History, 
  Loader2, 
  Download, 
  MoreVertical,
  ExternalLink,
  Filter,
  BarChart3,
  FileCheck2,
  AlertCircle
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Modal } from '../components/ui/Modal';
import { documentService, type Document } from '../services/documents';
import clsx from 'clsx';

const typeMap = {
  'quality_manual': { label: 'Manual de Calidad', icon: ShieldCheck, color: 'bg-primary/5 text-primary border-primary/10' },
  'procedure': { label: 'Procedimiento', icon: FileText, color: 'bg-blue-50 text-blue-500 border-blue-100' },
  'format': { label: 'Formato', icon: Files, color: 'bg-orange-50 text-orange-500 border-orange-100' },
  'instruction': { label: 'Instructivo', icon: FileText, color: 'bg-slate-50 text-slate-500 border-slate-100' },
  'registry': { label: 'Registro', icon: History, color: 'bg-green-50 text-green-500 border-green-100' },
};

const statusMap = {
  'draft': { label: 'Borrador', color: 'bg-slate-100 text-slate-500 border-slate-200' },
  'under_review': { label: 'En Revisión', color: 'bg-blue-100 text-blue-600 border-blue-200' },
  'approved': { label: 'Aprobado/Vigente', color: 'bg-green-100 text-green-600 border-green-200' },
  'archived': { label: 'Obsoleto', color: 'bg-red-100 text-red-600 border-red-200' },
  'expired': { label: 'Vencido', color: 'bg-orange-100 text-orange-600 border-orange-200' },
};

export function Documentos() {
  const [documents, setDocuments] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [uploadFile, setUploadFile] = useState<File | null>(null);

  const [newDoc, setNewDoc] = useState<Partial<Document>>({
    name: '',
    code: '',
    version: '1.0',
    type: 'procedure',
    status: 'draft'
  });

  const [selectedDoc, setSelectedDoc] = useState<Document | null>(null);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'details' | 'history' | 'approvals'>('details');
  const [versions, setVersions] = useState<any[]>([]);
  const [approvals, setApprovals] = useState<any[]>([]);

  const fetchData = async () => {
    try {
      setLoading(true);
      const data = await documentService.getDocuments();
      setDocuments(data);
    } catch (error) {
      console.error('Error fetching docs:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchDetailData = async (doc: Document) => {
    try {
      const [hist, apps] = await Promise.all([
        documentService.getVersionHistory(doc.id),
        documentService.getApprovals(doc.id)
      ]);
      setVersions(hist);
      setApprovals(apps);
    } catch (error) {
       console.error('Error fetching detail data:', error);
    }
  };

  const handleOpenDetail = (doc: Document) => {
    setSelectedDoc(doc);
    fetchDetailData(doc);
    setIsDetailOpen(true);
    setActiveTab('details');
  };

  const stats = useMemo(() => {
    return {
      total: documents.length,
      approved: documents.filter(d => d.status === 'approved').length,
      drafts: documents.filter(d => ['draft', 'under_review'].includes(d.status)).length,
      critical: documents.filter(d => d.type === 'procedure').length
    };
  }, [documents]);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      let file_url = null;
      if (uploadFile) {
        file_url = await documentService.uploadFile(uploadFile);
      }

      await documentService.createDocument({
        ...newDoc,
        file_url,
        approval_date: newDoc.status === 'approved' ? new Date().toISOString() : null
      });

      setIsModalOpen(false);
      setNewDoc({ name: '', code: '', version: '1.0', type: 'procedure', status: 'draft' });
      setUploadFile(null);
      fetchData();
    } catch (error) {
      console.error('Error creating doc:', error);
      alert('Error registrando documento. Verifica que la tabla "documents" exista en Supabase.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const filteredDocs = documents.filter(d => 
    d.name.toLowerCase().includes(search.toLowerCase()) || 
    d.code.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Sistema Normativo (DMS)</h1>
          <p className="text-xs font-bold text-slate-400">Control de documentos y registros según ISO 17025.</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 shadow-sm" />
            <input 
              type="text" 
              placeholder="Código o nombre..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-[1.25rem] py-3.5 pl-11 pr-4 text-[11px] font-black outline-none focus:ring-4 focus:ring-primary/5 transition-all shadow-sm"
            />
          </div>
          <Button 
            onClick={() => setIsModalOpen(true)}
            className="rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 shadow-xl shadow-primary/20 bg-primary border-none transition-all hover:scale-[1.03] active:scale-95 text-white"
          >
            <Plus className="w-5 h-5 stroke-[3px]" />
            CREAR DOCUMENTO
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-blue-50 rounded-2xl">
                  <BarChart3 className="w-5 h-5 text-blue-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Vigentes</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.approved}</span>
               <span className="text-[10px] font-black text-green-500 tracking-wide leading-none">Aprobados</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-orange-50 rounded-2xl">
                  <AlertCircle className="w-5 h-5 text-orange-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Borradores</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.drafts}</span>
               <span className="text-[10px] font-black text-orange-500 tracking-wide leading-none">En proceso</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-primary/5 rounded-2xl">
                  <FileCheck2 className="w-5 h-5 text-primary" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Total Catálogo</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.total}</span>
               <span className="text-[10px] font-black text-slate-400 tracking-wide leading-none">Documentos</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-slate-900 p-6 shadow-xl shadow-slate-200">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-white/10 rounded-2xl">
                  <ShieldCheck className="w-5 h-5 text-white" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Críticos</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-white tracking-tighter">{stats.critical}</span>
               <span className="text-[10px] font-black text-slate-500 tracking-wide leading-none uppercase">Estratégicos</span>
            </div>
         </Card>
      </div>

      <Card className="rounded-[2.5rem] border-none shadow-[0_12px_45px_-12px_rgba(0,0,0,0.05)] bg-white overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
           <div className="flex items-center gap-3">
              <Files className="w-5 h-5 text-slate-800" />
              <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest">Listado Maestro de Documentos</h2>
           </div>
           <button className="p-2 text-slate-400 hover:text-slate-800 transition-colors">
              <Filter className="w-5 h-5" />
           </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/30">
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Código</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Documento</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Categoría</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Versión</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Fecha Aprobación</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                [1,2,3,4,5].map(i => (
                  <tr key={i} className="animate-pulse">
                    <td colSpan={6} className="py-8 px-8"><div className="h-4 bg-slate-100 rounded-full w-full"></div></td>
                  </tr>
                ))
              ) : filteredDocs.length === 0 ? (
                <tr>
                   <td colSpan={6} className="py-12 text-center">
                      <div className="flex flex-col items-center gap-2 opacity-30">
                         <Files className="w-12 h-12" />
                         <p className="text-xs font-black uppercase tracking-widest">Catálogo vacío</p>
                      </div>
                   </td>
                </tr>
              ) : filteredDocs.map((doc) => (
                <tr key={doc.id} onClick={() => handleOpenDetail(doc)} className="hover:bg-slate-50/50 transition-colors group cursor-pointer">
                  <td className="py-6 px-8">
                     <span className="text-[11px] font-black text-slate-800 border-b-2 border-primary/20">
                        {doc.code}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <div className="flex items-center gap-3">
                        <div className="flex flex-col">
                           <span className="text-sm font-black text-slate-800 leading-tight group-hover:text-primary transition-colors">{doc.name}</span>
                           <span className={clsx("text-[9px] font-black uppercase tracking-widest inline-flex items-center gap-1.5 mt-1", statusMap[doc.status as keyof typeof statusMap]?.color || 'text-slate-400')}>
                              {doc.status === 'approved' && <FileCheck2 className="w-3 h-3" />}
                              {statusMap[doc.status as keyof typeof statusMap]?.label || doc.status.toUpperCase()}
                           </span>
                        </div>
                     </div>
                  </td>
                  <td className="py-6 px-8">
                     <span className={clsx("text-[9px] font-black uppercase tracking-widest px-3 py-1.5 rounded-xl border inline-flex items-center gap-2", typeMap[doc.type as keyof typeof typeMap]?.color || 'bg-slate-50 text-slate-400 border-slate-100')}>
                        {(() => {
                          const Icon = typeMap[doc.type as keyof typeof typeMap]?.icon || FileText;
                          return <Icon className="w-3.5 h-3.5" />;
                        })()}
                        {typeMap[doc.type as keyof typeof typeMap]?.label || doc.type}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <span className="text-[10px] font-black text-slate-500 bg-slate-100/50 px-2 py-1 rounded-lg">
                        v{doc.version}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <span className="text-[11px] font-bold text-slate-400">
                        {doc.approval_date ? new Date(doc.approval_date).toLocaleDateString() : 'Pendiente'}
                     </span>
                  </td>
                  <td className="py-6 px-8 text-right">
                     <div className="flex items-center justify-end gap-2">
                        {doc.file_url ? (
                           <button 
                             className="p-2.5 text-blue-500 hover:bg-blue-50 rounded-xl transition-all active:scale-95" 
                             onClick={(e) => { e.stopPropagation(); window.open(doc.file_url!, '_blank'); }}
                             title="Ver Documento"
                           >
                             <ExternalLink className="w-5 h-5" />
                           </button>
                        ) : (
                           <div className="p-2.5 text-slate-200">
                              <Files className="w-5 h-5" />
                           </div>
                        )}
                        <button className="p-2 text-slate-300 hover:text-slate-800 transition-colors">
                           <MoreVertical className="w-4 h-4" />
                        </button>
                     </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Card>

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Nuevo Documento Estratégico">
         <form onSubmit={handleCreate} className="space-y-6">
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Nombre del Documento / Formato</label>
               <input required placeholder="ej: Procedimiento General de Calibración" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newDoc.name} onChange={(e) => setNewDoc({...newDoc, name: e.target.value})} />
            </div>

            <div className="grid grid-cols-2 gap-6">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Código</label>
                  <input required placeholder="PRO-PRE-01" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newDoc.code} onChange={(e) => setNewDoc({...newDoc, code: e.target.value})} />
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Versión Actual</label>
                  <input required className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none" value={newDoc.version} onChange={(e) => setNewDoc({...newDoc, version: e.target.value})} />
               </div>
            </div>

            <div className="grid grid-cols-2 gap-6">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Tipo de Documento</label>
                  <select 
                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none appearance-none"
                    value={newDoc.type}
                    onChange={(e) => setNewDoc({...newDoc, type: e.target.value})}
                  >
                    {Object.entries(typeMap).map(([key, val]) => (
                      <option key={key} value={key}>{val.label}</option>
                    ))}
                  </select>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Estado Inicial</label>
                  <select 
                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none appearance-none"
                    value={newDoc.status}
                    onChange={(e) => setNewDoc({...newDoc, status: e.target.value as any})}
                  >
                    <option value="draft">Borrador / En revisión</option>
                    <option value="approved">Vigente / Aprobado</option>
                    <option value="archived">Obsoleto / Archivado</option>
                  </select>
               </div>
            </div>

            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Cargar Archivo (PDF, DOCX)</label>
               <div className="relative border-2 border-dashed border-slate-100 rounded-[2rem] p-8 flex flex-col items-center justify-center gap-3 hover:border-primary/30 transition-all bg-slate-50/50">
                  <Plus className="w-8 h-8 text-primary/30" />
                  <span className="text-[11px] font-black text-slate-400 uppercase tracking-widest">{uploadFile ? uploadFile.name : 'Seleccionar Documento'}</span>
                  <input type="file" className="absolute inset-0 opacity-0 cursor-pointer" onChange={(e) => setUploadFile(e.target.files?.[0] || null)} />
               </div>
            </div>

            <div className="flex gap-4 pt-4">
               <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="flex-1 h-13 rounded-2xl font-black border-slate-200">CANCELAR</Button>
               <Button type="submit" disabled={isSubmitting} className="flex-1 h-13 rounded-2xl font-black bg-primary text-white shadow-xl shadow-primary/20 gap-3">
                 {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                 APROBAR REGISTRO
               </Button>
            </div>
         </form>
      </Modal>

      <Modal isOpen={isDetailOpen} onClose={() => setIsDetailOpen(false)} title="Gestión de Documento DMS">
        {selectedDoc && (
          <div className="space-y-6">
            <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl">
              {(['details', 'history', 'approvals'] as const).map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={clsx(
                    "flex-1 py-2 px-4 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all",
                    activeTab === tab ? "bg-white text-slate-800 shadow-sm" : "text-slate-400 hover:text-slate-600"
                  )}
                >
                  {tab === 'details' ? 'Detalles' : tab === 'history' ? 'Historial v.' : 'Flujo'}
                </button>
              ))}
            </div>

            {activeTab === 'details' && (
              <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="grid grid-cols-2 gap-4">
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Código</p>
                    <p className="text-xs font-bold text-slate-800">{selectedDoc.code}</p>
                  </div>
                  <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Versión</p>
                    <p className="text-xs font-bold text-slate-800">v{selectedDoc.version}</p>
                  </div>
                </div>
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Estado Actual</p>
                  <p className={clsx("text-xs font-bold", statusMap[selectedDoc.status as keyof typeof statusMap]?.color || 'text-slate-800')}>
                    {statusMap[selectedDoc.status as keyof typeof statusMap]?.label || selectedDoc.status}
                  </p>
                </div>
                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                   <p className="text-[9px] font-black text-slate-400 uppercase mb-1">Norte de Cambio / Notas</p>
                   <p className="text-xs font-bold text-slate-600 italic">"{selectedDoc.revision_notes || 'Sin notas de cambio registradas'}"</p>
                </div>
                {selectedDoc.file_url && (
                   <Button onClick={() => window.open(selectedDoc.file_url!, '_blank')} className="w-full h-12 rounded-2xl bg-slate-900 text-white gap-2">
                      <Download className="w-5 h-5" /> VER ARCHIVO ACTUAL
                   </Button>
                )}
              </div>
            )}

            {activeTab === 'history' && (
              <div className="space-y-3 max-h-[400px] overflow-y-auto pr-2 custom-scrollbar animate-in fade-in slide-in-from-right-4 duration-300">
                {versions.length === 0 && <p className="text-center py-8 text-[10px] font-bold text-slate-400">No hay versiones anteriores.</p>}
                {versions.map(v => (
                  <div key={v.id} className="bg-white border border-slate-100 p-4 rounded-2xl hover:shadow-sm transition-all flex items-center justify-between group">
                    <div>
                      <div className="flex items-center gap-2">
                        <span className="text-xs font-black text-slate-800">v{v.version}</span>
                        <span className="text-[10px] font-bold text-slate-400">{new Date(v.created_at).toLocaleDateString()}</span>
                      </div>
                      <p className="text-[10px] text-slate-500 mt-1 line-clamp-1">{v.revision_notes}</p>
                    </div>
                    {v.file_url && (
                      <button onClick={() => window.open(v.file_url!, '_blank')} className="p-2 text-slate-400 hover:bg-slate-50 rounded-xl transition-all">
                        <Download className="w-4 h-4" />
                      </button>
                    )}
                  </div>
                ))}
              </div>
            )}

            {activeTab === 'approvals' && (
              <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                <div className="relative pl-8 space-y-8 before:absolute before:left-3.5 before:top-2 before:bottom-2 before:w-0.5 before:bg-slate-100">
                  <div className="relative">
                    <div className={clsx("absolute -left-8 top-1 w-7 h-7 rounded-full flex items-center justify-center ring-4 ring-white", selectedDoc.status === 'draft' ? "bg-orange-400" : "bg-green-500")}>
                      <Plus className="w-4 h-4 text-white" />
                    </div>
                    <div>
                      <p className="text-xs font-black text-slate-800">Creación / Borrador</p>
                      <p className="text-[10px] font-bold text-slate-400">Iniciado el {new Date(selectedDoc.created_at).toLocaleDateString()}</p>
                    </div>
                  </div>

                  {/* Dynamic Approvals Log */}
                  {approvals.map((app) => (
                    <div key={app.id} className="relative">
                      <div className={clsx(
                        "absolute -left-8 top-1 w-7 h-7 rounded-full flex items-center justify-center ring-4 ring-white transition-all",
                        app.status === 'approved' ? "bg-green-500" : app.status === 'rejected' ? "bg-red-500" : "bg-blue-500"
                      )}>
                        {app.step === 'review' ? <FileText className="w-4 h-4 text-white" /> : <ShieldCheck className="w-4 h-4 text-white" />}
                      </div>
                      <div className="flex flex-col">
                        <p className="text-xs font-black text-slate-800">
                          {app.step === 'review' ? 'Revisión Técnica' : 'Aprobación Calidad'} 
                          <span className={clsx("ml-2 px-1.5 py-0.5 rounded text-[8px] uppercase", app.status === 'approved' ? 'bg-green-100 text-green-600' : app.status === 'rejected' ? 'bg-red-100 text-red-600' : 'bg-blue-100 text-blue-600')}>
                            {app.status === 'approved' ? 'Hecho' : app.status === 'rejected' ? 'Rechazado' : 'Pendiente'}
                          </span>
                        </p>
                        <p className="text-[10px] font-bold text-slate-400">{app.assigned_to}</p>
                        {app.comments && <p className="text-[10px] text-slate-500 italic mt-1 bg-slate-50 p-2 rounded-lg border border-slate-100">"{app.comments}"</p>}
                      </div>
                    </div>
                  ))}

                  {/* Fallback Static if no approvals yet */}
                  {approvals.length === 0 && selectedDoc.status !== 'draft' && (
                    <div className="relative opacity-50">
                      <div className="absolute -left-8 top-1 w-7 h-7 rounded-full bg-slate-200 flex items-center justify-center ring-4 ring-white">
                        <Loader2 className="w-4 h-4 text-slate-400" />
                      </div>
                      <div>
                        <p className="text-xs font-black text-slate-400">Procesando Flujo...</p>
                      </div>
                    </div>
                  )}
                </div>

                {selectedDoc.status === 'draft' && (
                   <div className="bg-blue-50/50 p-6 rounded-[2rem] border border-blue-100/50 space-y-4">
                      <p className="text-[10px] font-black text-blue-600 uppercase tracking-widest text-center">Acciones de Flujo</p>
                      <Button 
                        onClick={() => documentService.requestApproval(selectedDoc.id, 'Jefe de Laboratorio', 'review').then(() => { fetchData(); fetchDetailData(selectedDoc); setIsDetailOpen(false); })} 
                        className="w-full h-13 rounded-2xl bg-blue-600 text-white shadow-lg shadow-blue-200"
                      >
                         SOLICITAR REVISIÓN
                      </Button>
                   </div>
                )}

                {selectedDoc.status === 'under_review' && (
                   <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 space-y-4">
                      <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest text-center">Control de Calidad</p>
                      <div className="flex gap-4">
                        <Button 
                          onClick={() => {
                            const role = selectedDoc.reviewer_name && !selectedDoc.approver_name ? 'reviewer' : 'approver';
                            documentService.approveDocument(selectedDoc, role as any, `Aprobado en paso: ${role}`)
                              .then(() => { fetchData(); fetchDetailData(selectedDoc); setIsDetailOpen(false); });
                          }}
                          className="flex-1 h-13 rounded-2xl bg-green-500 text-white shadow-lg shadow-green-200"
                        >
                          APROBAR
                        </Button>
                        <Button 
                          onClick={() => documentService.rejectDocument(selectedDoc.id, 'Solicitud de corrección técnica.')
                            .then(() => { fetchData(); fetchDetailData(selectedDoc); setIsDetailOpen(false); })}
                          variant="outline" 
                          className="flex-1 h-13 rounded-2xl border-red-200 text-red-500"
                        >
                          RECHAZAR
                        </Button>
                      </div>
                   </div>
                )}
              </div>
            )}
          </div>
        )}
      </Modal>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { 
  Plus, 
  Search, 
  Settings2, 
  Edit2, 
  Trash2, 
  Monitor, 
  AlertCircle,
  Loader2,
  CheckCircle2,
  XCircle,
  Clock,
  Filter,
  Tag,
  Hash,
  ChevronRight,
  Camera,
  Upload,
  Image as ImageIcon,
  X
} from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { equipmentService, type Equipment } from '../services/equipment';
import { magnitudesService, type Magnitude } from '../services/magnitudes';
import { Modal } from '../components/ui/Modal';
import { PermissionGuard } from '../components/PermissionGuard';
import { format, addDays, differenceInDays } from 'date-fns';
import { es } from 'date-fns/locale';
import clsx from 'clsx';

const statusColorMap: Record<string, string> = {
  'active': 'text-green-600 bg-green-50 border-green-100',
  'pending_calibration': 'text-orange-600 bg-orange-50 border-orange-100',
  'maintenance': 'text-blue-600 bg-blue-50 border-blue-100',
  'out_of_service': 'text-red-600 bg-red-50 border-red-100',
};

const statusIconMap: Record<string, any> = {
  'active': CheckCircle2,
  'pending_calibration': Clock,
  'maintenance': Settings2,
  'out_of_service': XCircle,
};

const statusLabelMap: Record<string, string> = {
  'active': 'Operativo',
  'pending_calibration': 'Calibración Pendiente',
  'maintenance': 'En Mantenimiento',
  'out_of_service': 'Fuera de Servicio',
};

export function Equipos() {
  const [equipmentList, setEquipmentList] = useState<Equipment[]>([]);
  const [magnitudes, setMagnitudes] = useState<Magnitude[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [search, setSearch] = useState('');
  const [magnitudeFilter, setMagnitudeFilter] = useState('all');

  // Form Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingEquipment, setEditingEquipment] = useState<Equipment | null>(null);
  const [newEquipment, setNewEquipment] = useState<Partial<Equipment>>({
    name: '',
    brand: '',
    model: '',
    serial_number: '',
    internal_id: '',
    magnitude_id: '',
    status: 'active',
    image_url: null,
    calibration_period_days: 365,
    last_calibration_date: null
  });

  // Image Preview State
  const [imagePreview, setImagePreview] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Delete Modal State
  const [isDeleteOpen, setIsDeleteOpen] = useState(false);
  const [equipmentToDelete, setEquipmentToDelete] = useState<Equipment | null>(null);

  const fetchData = async () => {
    try {
      setLoading(true);
      const [eData, mData] = await Promise.all([
        equipmentService.getAll(),
        magnitudesService.getAll()
      ]);
      setEquipmentList(eData);
      setMagnitudes(mData);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setImagePreview(reader.result as string);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      let finalImageUrl = newEquipment.image_url;

      // Handle File Upload if changed
      if (fileInputRef.current?.files?.[0]) {
        try {
          finalImageUrl = await equipmentService.uploadImage(fileInputRef.current.files[0]);
        } catch (error) {
          console.error('Error uploading image:', error);
          alert('Error al subir la imagen. Verifica que el cubo "managemet_assets" exista en Supabase.');
        }
      }

      const eqToSave = { ...newEquipment, image_url: finalImageUrl };

      if (editingEquipment) {
        await equipmentService.update(editingEquipment.id, eqToSave);
      } else {
        await equipmentService.create(eqToSave);
      }
      setIsModalOpen(false);
      resetForm();
      fetchData();
    } catch (error) {
      console.error('Error saving equipment:', error);
      alert('Error guardando el equipo. Revisa la base de datos.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!equipmentToDelete) return;
    setIsSubmitting(true);
    try {
      await equipmentService.delete(equipmentToDelete.id);
      setIsDeleteOpen(false);
      setEquipmentToDelete(null);
      fetchData();
    } catch (error) {
      console.error('Error deleting equipment:', error);
      alert('No se pudo eliminar el equipo.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const resetForm = () => {
    setEditingEquipment(null);
    setNewEquipment({
      name: '', brand: '', model: '', serial_number: '', internal_id: '', magnitude_id: '', status: 'active', image_url: null, calibration_period_days: 365, last_calibration_date: null
    });
    setImagePreview(null);
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const handleEdit = (equipment: Equipment) => {
    setEditingEquipment(equipment);
    setNewEquipment({
      name: equipment.name,
      brand: equipment.brand || '',
      model: equipment.model || '',
      serial_number: equipment.serial_number || '',
      internal_id: equipment.internal_id || '',
      magnitude_id: equipment.magnitude_id,
      status: equipment.status,
      image_url: equipment.image_url,
      calibration_period_days: equipment.calibration_period_days || 365,
      last_calibration_date: equipment.last_calibration_date
    });
    setImagePreview(equipment.image_url);
    setIsModalOpen(true);
  };

  const filteredEquipment = equipmentList.filter(e => {
    const matchesSearch = e.name.toLowerCase().includes(search.toLowerCase()) || 
                          e.internal_id?.toLowerCase().includes(search.toLowerCase());
    const matchesMagnitude = magnitudeFilter === 'all' || e.magnitude_id === magnitudeFilter;
    return matchesSearch && matchesMagnitude;
  });

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Inventario de Equipos</h1>
          <p className="text-xs font-bold text-slate-400">Control de instrumentos de medición y aseguramiento metrológico</p>
        </div>

        <div className="flex flex-wrap items-center gap-4">
           {/* Filters */}
           <div className="flex items-center gap-3 bg-white p-1.5 rounded-3xl border border-slate-100 shadow-sm">
             <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                <input 
                  type="text" 
                  placeholder="ID Interno o nombre..." 
                  className="bg-transparent border-none py-2 pl-10 pr-4 text-[11px] font-black outline-none w-56 placeholder:text-slate-300"
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                />
             </div>
             <div className="h-6 w-px bg-slate-100" />
             <div className="relative flex items-center pr-2">
                <Filter className="w-4 h-4 text-slate-400 ml-2 mr-2" />
                <select 
                  className="bg-transparent border-none text-[11px] font-black uppercase text-slate-500 outline-none cursor-pointer pr-4 hover:text-primary transition-colors"
                  value={magnitudeFilter}
                  onChange={(e) => setMagnitudeFilter(e.target.value)}
                >
                  <option value="all">Todas las Magnitudes</option>
                  {magnitudes.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                </select>
             </div>
           </div>

           <PermissionGuard module="equipos" action="create">
             <Button 
              onClick={() => { resetForm(); setIsModalOpen(true); }}
              className="rounded-[1.25rem] h-12 px-8 font-black flex items-center gap-3 shadow-xl shadow-primary/20 bg-primary text-white border-none transition-all hover:scale-[1.03] active:scale-95 text-xs tracking-wide"
             >
              <Plus className="w-5 h-5 stroke-[3px]" />
              NUEVO REGISTRO
            </Button>
           </PermissionGuard>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-3 gap-8">
        {loading ? (
          [1,2,3,4,5,6].map(i => <div key={i} className="h-80 bg-slate-100/50 rounded-[3rem] animate-pulse" />)
        ) : filteredEquipment.length === 0 ? (
          <div className="col-span-full h-96 flex flex-col items-center justify-center text-center p-12 bg-white rounded-[4rem] border-2 border-dashed border-slate-100 shadow-sm">
             <div className="w-24 h-24 bg-slate-50 rounded-full flex items-center justify-center mb-8 ring-8 ring-slate-50/50">
                <Monitor className="w-10 h-10 text-slate-200" />
             </div>
             <p className="text-2xl font-black text-slate-800 mb-2">Sin equipos registrados</p>
             <p className="text-sm font-bold text-slate-400 max-w-sm">No hay instrumentos que coincidan con tus filtros actuales.</p>
          </div>
        ) : (
          filteredEquipment.map((equipment: any) => {
            const StatusIcon = statusIconMap[equipment.status] || Monitor;
            const statusClass = statusColorMap[equipment.status] || 'bg-slate-50 text-slate-400';

            return (
              <Card key={equipment.id} className="border-none shadow-[0_12px_45px_-12px_rgba(0,0,0,0.05)] rounded-[3rem] bg-white group hover:scale-[1.03] hover:shadow-[0_45px_100px_-20px_rgba(0,0,0,0.08)] transition-all duration-500 overflow-hidden border border-white hover:border-slate-100 flex flex-col">
                <CardContent className="p-0 flex flex-col h-full flex-1 relative">
                  {/* Image Placeholder or Actual Image */}
                  <div className="h-40 w-full bg-slate-50 relative overflow-hidden flex items-center justify-center transition-all duration-500 group-hover:bg-slate-100 p-4">
                     {equipment.image_url ? (
                       <img src={equipment.image_url} alt={equipment.name} className="w-full h-full object-contain transition-transform duration-700 group-hover:scale-105" />
                     ) : (
                       <ImageIcon className="w-10 h-10 text-slate-200 group-hover:scale-110 transition-transform duration-500" />
                     )}
                     <div className="absolute top-4 left-6 flex flex-col gap-1">
                        <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest leading-none">ID Interno</span>
                        <span className="text-[11px] font-black text-slate-700 bg-white/80 backdrop-blur-md px-3 py-1 rounded-lg border border-slate-100 shadow-sm">
                          {equipment.internal_id || 'PROTOTYPE'}
                        </span>
                     </div>
                     <div className="absolute top-4 right-6 flex gap-1.5 translate-y-2 opacity-0 group-hover:translate-y-0 group-hover:opacity-100 transition-all duration-300">
                        <button onClick={() => handleEdit(equipment)} className="p-2.5 bg-white/90 backdrop-blur-md text-slate-600 hover:text-primary hover:bg-white rounded-xl shadow-xl active:scale-90 transition-all">
                          <Edit2 className="w-3.5 h-3.5" />
                        </button>
                        <button onClick={() => { setEquipmentToDelete(equipment); setIsDeleteOpen(true); }} className="p-2.5 bg-white/90 backdrop-blur-md text-slate-600 hover:text-red-500 hover:bg-white rounded-xl shadow-xl active:scale-90 transition-all focus:outline-none">
                          <Trash2 className="w-3.5 h-3.5" />
                        </button>
                     </div>
                  </div>

                  <div className="p-8 flex-1 flex flex-col">
                    <div className="flex items-center gap-2 mb-3">
                      <div className="w-2 h-2 rounded-full bg-primary ring-4 ring-primary/10" />
                      <span className="text-[10px] font-black text-primary uppercase tracking-widest">{(equipment as any).magnitude?.name}</span>
                    </div>
                    <h3 className="text-2xl font-black text-slate-800 mb-4 truncate leading-none capitalize" title={equipment.name}>{equipment.name}</h3>

                    <div className="grid grid-cols-2 gap-4 mb-4">
                       <div className="flex flex-col gap-1">
                         <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Marca</span>
                         <span className="text-xs font-bold text-slate-600 truncate">{equipment.brand || '-'}</span>
                       </div>
                       <div className="flex flex-col gap-1">
                         <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest">Modelo</span>
                         <span className="text-xs font-bold text-slate-600 truncate">{equipment.model || '-'}</span>
                       </div>
                    </div>

                    <div className="space-y-3 mb-8 pt-4 border-t border-slate-50">
                       <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Trazabilidad Metrológica</span>
                       <div className="flex items-center justify-between">
                          <div className="flex flex-col">
                             <span className="text-[9px] font-bold text-slate-400">Última: {equipment.last_calibration_date ? format(new Date(equipment.last_calibration_date), 'dd/MM/yy') : 'N/A'}</span>
                             {equipment.last_calibration_date && (
                                <span className="text-[9px] font-bold text-slate-500">
                                   Próxima: {format(addDays(new Date(equipment.last_calibration_date), equipment.calibration_period_days || 365), 'dd/MM/yy')}
                                </span>
                             )}
                          </div>
                          {(() => {
                             if (!equipment.last_calibration_date) return null;
                             const next = addDays(new Date(equipment.last_calibration_date), equipment.calibration_period_days || 365);
                             const diff = differenceInDays(next, new Date());
                             let stat = { label: 'Vigente', color: 'bg-green-500 shadow-green-100' };
                             if (diff < 0) stat = { label: 'Vencido', color: 'bg-red-500 shadow-red-100' };
                             else if (diff <= 30) stat = { label: 'Próximo', color: 'bg-orange-500 shadow-orange-100' };

                             return (
                                <div className={clsx("px-3 py-1 rounded-full text-[8px] font-black text-white uppercase tracking-wider shadow-lg", stat.color)}>
                                   {stat.label}
                                </div>
                             );
                          })()}
                       </div>
                    </div>

                    <div className="flex items-center justify-between pt-6 border-t border-slate-50 mt-auto">
                       <div className={clsx("flex items-center gap-2 px-4 py-2 rounded-2xl border text-[10px] font-black transition-all duration-300 group-hover:shadow-lg shadow-sm border-transparent", statusClass)}>
                          <StatusIcon className="w-4 h-4" />
                          {statusLabelMap[equipment.status].toUpperCase()}
                       </div>
                       <button className="flex items-center gap-2 text-[10px] font-black text-primary hover:gap-3 transition-all hover:text-slate-900 group/btn">
                         EXPEDIENTE 
                         <div className="p-1.5 bg-primary/5 rounded-lg group-hover/btn:bg-primary/10">
                           <ChevronRight className="w-4 h-4" />
                         </div>
                       </button>
                    </div>
                  </div>
                </CardContent>
              </Card>
            );
          })
        )}
      </div>

      {/* FORM MODAL */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={editingEquipment ? 'Editar Instrumento' : 'Nuevo Instrumento Técnico'}
      >
        <form onSubmit={handleSubmit} className="space-y-6 max-h-[75vh] overflow-y-auto pr-4 custom-scrollbar">
           {/* Image Upload Area */}
           <div className="relative group/pic">
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="w-full h-48 bg-slate-50 rounded-[2.5rem] border-2 border-dashed border-slate-100 flex flex-col items-center justify-center cursor-pointer hover:border-primary/30 hover:bg-primary/5 transition-all relative overflow-hidden"
              >
                {imagePreview ? (
                  <>
                    <img src={imagePreview} alt="Preview" className="w-full h-full object-cover" />
                    <div className="absolute inset-0 bg-black/20 backdrop-blur-[2px] opacity-0 group-hover/pic:opacity-100 transition-opacity flex items-center justify-center">
                       <Camera className="w-10 h-10 text-white" />
                    </div>
                    <button 
                      type="button"
                      onClick={(e) => { e.stopPropagation(); setImagePreview(null); if (fileInputRef.current) fileInputRef.current.value = ''; }}
                      className="absolute top-4 right-4 p-2 bg-white/90 rounded-xl text-red-500 shadow-xl hover:bg-white"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  </>
                ) : (
                  <>
                    <div className="w-16 h-16 bg-white rounded-3xl flex items-center justify-center shadow-lg mb-4 text-slate-300 group-hover/pic:text-primary group-hover/pic:scale-110 transition-all">
                       <Camera className="w-8 h-8" />
                    </div>
                    <p className="text-xs font-black text-slate-400 uppercase tracking-widest">Cargar fotografía del equipo</p>
                  </>
                )}
              </div>
              <input 
                type="file" 
                hidden 
                accept="image/*" 
                ref={fileInputRef}
                onChange={handleImageChange}
              />
           </div>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pb-2">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Nombre Equipo</label>
                <input required placeholder="ej: Manómetro Digital" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.name || ""} onChange={(e) => setNewEquipment({ ...newEquipment, name: e.target.value })} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Magnitud</label>
                <select required className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.magnitude_id || ""} onChange={(e) => setNewEquipment({ ...newEquipment, magnitude_id: e.target.value })}>
                   <option value="">Seleccione magnitud</option>
                   {magnitudes.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">ID Interno</label>
                <input required placeholder="ej: PAT-001" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.internal_id || ""} onChange={(e) => setNewEquipment({ ...newEquipment, internal_id: e.target.value })} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Marca</label>
                <input placeholder="ej: Fluke" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.brand || ""} onChange={(e) => setNewEquipment({ ...newEquipment, brand: e.target.value })} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Modelo</label>
                <input placeholder="ej: 700G" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.model || ""} onChange={(e) => setNewEquipment({ ...newEquipment, model: e.target.value })} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Número de Serie</label>
                <input placeholder="ej: SN-123456" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.serial_number || ""} onChange={(e) => setNewEquipment({ ...newEquipment, serial_number: e.target.value })} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Última Calibración</label>
                <input type="date" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.last_calibration_date || ""} onChange={(e) => setNewEquipment({ ...newEquipment, last_calibration_date: e.target.value })} />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Periodo (Días)</label>
                <input type="number" placeholder="365" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none" value={newEquipment.calibration_period_days || ''} onChange={(e) => setNewEquipment({ ...newEquipment, calibration_period_days: parseInt(e.target.value) || 0 })} />
              </div>

              {newEquipment.last_calibration_date && newEquipment.calibration_period_days && (
                 <div className="col-span-full p-6 bg-primary/5 rounded-[2rem] border border-primary/10 flex items-center justify-between">
                    <span className="text-[10px] font-black text-primary uppercase tracking-widest">Próxima Calibración Calculada:</span>
                    <span className="text-sm font-black text-slate-800">
                       {format(addDays(new Date(newEquipment.last_calibration_date), newEquipment.calibration_period_days), "dd 'de' MMMM, yyyy", { locale: es })}
                    </span>
                 </div>
              )}

              <div className="col-span-full space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Estado Operativo</label>
                <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
                   {Object.keys(statusLabelMap).map(s => {
                     const isSelected = newEquipment.status === s;
                     const Icon = statusIconMap[s];
                     return (
                       <button
                         key={s}
                         type="button"
                         onClick={() => setNewEquipment({ ...newEquipment, status: s as any })}
                         className={clsx(
                           "flex flex-col items-center gap-2 p-4 rounded-2xl border-2 transition-all",
                           isSelected ? "bg-primary/5 border-primary text-primary shadow-lg shadow-primary/5" : "bg-white border-slate-50 text-slate-400 hover:border-slate-100"
                         )}
                       >
                         <Icon className="w-5 h-5" />
                         <span className="text-[10px] font-bold text-center leading-tight">{statusLabelMap[s]}</span>
                       </button>
                     );
                   })}
                </div>
              </div>
           </div>

           <div className="flex gap-4 pt-4 sticky bottom-0 bg-white/80 backdrop-blur-md pb-2">
              <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="flex-1 h-12 rounded-2xl font-black border-slate-200 uppercase text-[10px] tracking-widest">CANCELAR</Button>
              <Button type="submit" disabled={isSubmitting} className="flex-1 h-13 rounded-2xl font-black bg-primary text-white shadow-xl shadow-primary/20 uppercase text-[10px] tracking-widest gap-3">
                {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                {editingEquipment ? 'GUARDAR CAMBIOS' : 'VINCULAR EQUIPO'}
              </Button>
           </div>
        </form>
      </Modal>

      {/* DELETE MODAL */}
      <Modal isOpen={isDeleteOpen} onClose={() => setIsDeleteOpen(false)} title="Confirmar Eliminación">
        <div className="space-y-8 text-center py-6">
           <div className="w-24 h-24 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 ring-8 ring-red-50/50">
              <AlertCircle className="w-12 h-12 text-red-500" />
           </div>
           <p className="text-base font-bold text-slate-600 leading-relaxed px-4">
             ¿Estás seguro de que quieres eliminar el equipo <br/>
             <span className="text-slate-900 font-black text-xl">"{equipmentToDelete?.name}"</span>?
           </p>
           <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Esta acción eliminará también su historial vinculado.</p>

           <div className="flex gap-4 px-6 pt-4">
              <Button variant="outline" onClick={() => setIsDeleteOpen(false)} className="flex-1 h-14 rounded-[1.5rem] font-black border-slate-200">CANCELAR</Button>
              <Button variant="destructive" disabled={isSubmitting} onClick={handleDelete} className="flex-1 h-14 rounded-[1.5rem] font-black bg-red-500 hover:bg-red-600 shadow-xl shadow-red-200 text-white">
                {isSubmitting && <Loader2 className="w-4 h-4 animate-spin mr-2" />}
                SÍ, ELIMINAR
              </Button>
           </div>
        </div>
      </Modal>
    </div>
  );
}

import { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { LogIn, Mail, Lock, Loader2 } from 'lucide-react';

export function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);
    try {
      const { error } = await supabase.auth.signInWithPassword({ email, password });
      if (error) throw error;
    } catch (err: any) {
      setError(err.message || 'Error al iniciar sesión');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-6 animate-in fade-in duration-1000">
      <Card className="w-full max-w-md rounded-[3rem] border-none shadow-2xl shadow-slate-200 overflow-hidden bg-white">
        <div className="p-12 space-y-8">
          <div className="text-center space-y-2">
            <div className="w-16 h-16 bg-primary/10 rounded-2xl flex items-center justify-center mx-auto mb-6">
              <LogIn className="w-8 h-8 text-primary" />
            </div>
            <h1 className="text-3xl font-black tracking-tight text-slate-800 uppercase">ManageMet</h1>
            <p className="text-xs font-bold text-slate-400">Panel de Control Metrológico</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="space-y-4">
              <div className="relative group">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-hover:text-primary transition-colors" />
                <input 
                  type="email" 
                  placeholder="Email corporativo" 
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full bg-slate-50 border-none rounded-2xl py-4 pl-12 pr-6 text-sm font-bold outline-none focus:ring-4 focus:ring-primary/5 transition-all"
                />
              </div>
              <div className="relative group">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 group-hover:text-primary transition-colors" />
                <input 
                  type="password" 
                  placeholder="Contraseña" 
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full bg-slate-50 border-none rounded-2xl py-4 pl-12 pr-6 text-sm font-bold outline-none focus:ring-4 focus:ring-primary/5 transition-all"
                />
              </div>
            </div>

            {error && (
              <div className="p-4 bg-red-50 rounded-2xl border border-red-100">
                <p className="text-[11px] font-bold text-red-500 text-center uppercase tracking-wide">{error}</p>
              </div>
            )}

            <Button 
              type="submit" 
              disabled={loading}
              className="w-full h-14 rounded-2xl bg-primary text-white font-black text-sm shadow-xl shadow-primary/25 hover:scale-[1.03] active:scale-95 transition-all"
            >
              {loading ? <Loader2 className="w-5 h-5 animate-spin mx-auto" /> : 'ENTRAR AL SISTEMA'}
            </Button>
          </form>

          <div className="text-center">
             <p className="text-[10px] font-black text-slate-300 uppercase tracking-widest leading-none">© 2026 Bustillo Ingeniería</p>
          </div>
        </div>
      </Card>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { 
  Plus, 
  Search, 
  Layers, 
  Thermometer, 
  Gauge, 
  Weight, 
  Scaling, 
  Droplets,
  Edit2,
  Trash2,
  ChevronRight,
  AlertCircle,
  Loader2,
  Settings2,
  History,
  FileText,
  Target,
  Ruler,
  Activity
} from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { magnitudesService, type Magnitude } from '../services/magnitudes';
import { Modal } from '../components/ui/Modal';
import clsx from 'clsx';

const iconMap: Record<string, any> = {
  'Temperatura': Thermometer,
  'Presión': Gauge,
  'Masa': Weight,
  'Longitud': Scaling,
  'Volumen': Droplets,
  'Humedad': Droplets,
};

const colorMap: Record<string, string> = {
  'Temperatura': 'text-orange-500 bg-orange-50',
  'Presión': 'text-blue-500 bg-blue-50',
  'Masa': 'text-slate-700 bg-slate-100',
  'Longitud': 'text-teal-500 bg-teal-50',
  'Volumen': 'text-cyan-500 bg-cyan-50',
  'Humedad': 'text-blue-600 bg-blue-50',
};

export function Magnitudes() {
  const [magnitudes, setMagnitudes] = useState<Magnitude[]>([]);
  const [loading, setLoading] = useState(true);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [search, setSearch] = useState('');

  // CRUD Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingMagnitude, setEditingMagnitude] = useState<Magnitude | null>(null);
  const [newMagnitude, setNewMagnitude] = useState({ name: '', description: '' });

  // Config Modal State
  const [isConfigOpen, setIsConfigOpen] = useState(false);
  const [configMagnitude, setConfigMagnitude] = useState<Magnitude | null>(null);

  // Delete Confirmation State
  const [isDeleteOpen, setIsDeleteOpen] = useState(false);
  const [magnitudeToDelete, setMagnitudeToDelete] = useState<Magnitude | null>(null);

  const fetchMagnitudes = async () => {
    try {
      setLoading(true);
      const data = await magnitudesService.getAll();
      setMagnitudes(data);
    } catch (error) {
      console.error('Error fetching magnitudes:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchMagnitudes();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
      if (editingMagnitude) {
        await magnitudesService.update(editingMagnitude.id, newMagnitude);
      } else {
        await magnitudesService.create(newMagnitude);
      }
      setIsModalOpen(false);
      setNewMagnitude({ name: '', description: '' });
      setEditingMagnitude(null);
      fetchMagnitudes();
    } catch (error) {
      console.error('Error saving magnitude:', error);
      alert('Error al guardar la magnitud. Revisa si el nombre ya existe.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleDelete = async () => {
    if (!magnitudeToDelete) return;
    setIsSubmitting(true);
    try {
      await magnitudesService.delete(magnitudeToDelete.id);
      setIsDeleteOpen(false);
      setMagnitudeToDelete(null);
      fetchMagnitudes();
    } catch (error) {
      console.error('Error deleting magnitude:', error);
      alert('Error al eliminar la magnitud.');
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleEdit = (magnitude: Magnitude) => {
    setEditingMagnitude(magnitude);
    setNewMagnitude({ name: magnitude.name, description: magnitude.description || '' });
    setIsModalOpen(true);
  };

  const confirmDelete = (magnitude: Magnitude) => {
    setMagnitudeToDelete(magnitude);
    setIsDeleteOpen(true);
  };

  const handleConfig = (magnitude: Magnitude) => {
    setConfigMagnitude(magnitude);
    setIsConfigOpen(true);
  };

  const filteredMagnitudes = magnitudes.filter(m => 
    m.name.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Magnitudes Metrológicas</h1>
          <p className="text-xs font-bold text-slate-400 font-sans">Gestiona las magnitudes físicas y sus configuraciones base (ISO 17025)</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative w-64">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder="Buscar magnitud..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-2xl py-3 pl-11 pr-4 text-xs font-bold focus:outline-none focus:ring-2 focus:ring-primary/20 transition-all placeholder:text-slate-400 shadow-[0_4px_12px_rgb(0,0,0,0.01)]"
            />
          </div>
          <Button 
            onClick={() => {
              setEditingMagnitude(null);
              setNewMagnitude({ name: '', description: '' });
              setIsModalOpen(true);
            }}
            className="rounded-2xl h-12 px-8 font-bold flex items-center gap-2 shadow-lg shadow-primary/20 transition-all hover:scale-105 active:scale-95 bg-primary text-white border-0"
          >
            <Plus className="w-5 h-5" />
            Nueva Magnitud
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {loading ? (
          [1,2,3].map(i => (
            <div key={i} className="h-48 bg-slate-100/50 rounded-[2.5rem] animate-pulse border border-slate-50" />
          ))
        ) : filteredMagnitudes.length === 0 ? (
          <div className="col-span-full h-96 flex flex-col items-center justify-center text-center p-10 bg-white rounded-[3rem] border-2 border-dashed border-slate-100 shadow-sm shadow-slate-200/20">
             <div className="w-20 h-20 bg-slate-50 rounded-full flex items-center justify-center mb-6 ring-8 ring-slate-50/50">
                <Layers className="w-10 h-10 text-slate-300" />
             </div>
             <p className="text-xl font-black text-slate-800 mb-2">No hay magnitudes</p>
             <p className="text-sm font-bold text-slate-400 mb-8 max-w-sm">
               Empieza agregando las magnitudes físicas que tu laboratorio gestiona.
             </p>
             <Button 
               onClick={async () => {
                 const seed = [
                   { name: 'Temperatura', description: 'Magnitud física que expresa el grado de calor.' },
                   { name: 'Presión', description: 'Fuerza que ejerce un gas o líquido.' },
                   { name: 'Masa', description: 'Cantidad de materia de un cuerpo.' },
                 ];
                 for (const m of seed) {
                   await magnitudesService.create(m as Partial<Magnitude>);
                 }
                 fetchMagnitudes();
               }}
               variant="outline" 
               className="rounded-2xl h-11 px-8 font-black border-slate-200 hover:bg-slate-50 transition-all"
             >
               Cargar Magnitudes Base
             </Button>
          </div>
        ) : (
          filteredMagnitudes.map((magnitude: Magnitude) => {
            const Icon = iconMap[magnitude.name] || Layers;
            const colorClass = colorMap[magnitude.name] || 'text-slate-500 bg-slate-50';

            return (
              <Card key={magnitude.id} className="border-none shadow-[0_8px_30px_rgb(0,0,0,0.02)] rounded-[2.5rem] overflow-hidden group hover:scale-[1.02] hover:shadow-[0_20px_60px_rgb(0,0,0,0.03)] transition-all duration-300 bg-white p-8 border border-white hover:border-slate-100 flex flex-col h-full">
                <CardContent className="p-0 flex flex-col flex-1">
                  <div className="flex justify-between items-start mb-6">
                    <div className={clsx("p-4 rounded-3xl transition-all duration-500 group-hover:rotate-6 shadow-sm", colorClass)}>
                      <Icon className="w-6 h-6" />
                    </div>
                    <div className="flex gap-2">
                      <button 
                        onClick={() => handleEdit(magnitude)}
                        className="p-3 text-slate-300 hover:text-primary hover:bg-blue-50/50 rounded-2xl transition-all active:scale-90"
                      >
                         <Edit2 className="w-4 h-4" />
                      </button>
                      <button 
                        onClick={() => confirmDelete(magnitude)}
                        className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-2xl transition-all active:scale-90"
                      >
                         <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </div>

                  <div className="mb-8 flex-1">
                    <h3 className="text-xl font-black text-slate-800 mb-2 group-hover:text-primary transition-colors">{magnitude.name}</h3>
                    <p className="text-xs font-bold text-slate-400 line-clamp-2 leading-relaxed">
                      {magnitude.description || 'Sin descripción técnica parametrizada.'}
                    </p>
                  </div>

                  <div className="flex items-center justify-between pt-6 border-t border-slate-50">
                     <div className="flex flex-col">
                       <span className="text-[10px] font-black text-slate-300 uppercase tracking-[0.15em] mb-1">Configuración</span>
                       <span className="text-sm font-black text-slate-700">ISO 17025</span>
                     </div>
                     <button 
                       onClick={() => handleConfig(magnitude)}
                       className="flex items-center gap-1.5 text-[11px] font-black text-primary hover:gap-3 transition-all"
                     >
                        Configurar <ChevronRight className="w-4 h-4" />
                     </button>
                  </div>
                </CardContent>
              </Card>
            );
          })
        )}
      </div>

      {/* CREATE / EDIT MODAL */}
      <Modal 
        isOpen={isModalOpen} 
        onClose={() => setIsModalOpen(false)} 
        title={editingMagnitude ? 'Editar Magnitud' : 'Nueva Magnitud'}
      >
        <form onSubmit={handleSubmit} className="space-y-8">
           <div className="space-y-2">
             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Nombre Magnitude</label>
             <input 
               required
               placeholder="ej: Temperatura"
               className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none"
               value={newMagnitude.name}
               onChange={(e) => setNewMagnitude({ ...newMagnitude, name: e.target.value })}
             />
           </div>

           <div className="space-y-2">
             <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Descripción técnica</label>
             <textarea 
               rows={3}
               placeholder="Describe brevemente la magnitud..."
               className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none"
               value={newMagnitude.description}
               onChange={(e) => setNewMagnitude({ ...newMagnitude, description: e.target.value })}
             />
           </div>

           <div className="pt-4 flex gap-4">
              <Button 
                type="button" 
                variant="outline" 
                onClick={() => setIsModalOpen(false)}
                className="flex-1 h-12 rounded-2xl font-bold border-slate-200"
              >
                Cancelar
              </Button>
              <Button 
                type="submit" 
                disabled={isSubmitting}
                className="flex-1 h-12 rounded-2xl font-bold gap-2 shadow-lg shadow-primary/20 bg-primary text-white"
              >
                {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                {editingMagnitude ? 'Guardar Cambios' : 'Crear Magnitud'}
              </Button>
           </div>
        </form>
      </Modal>

      {/* CONFIGURATION MODAL (The new one) */}
      <Modal 
        isOpen={isConfigOpen} 
        onClose={() => setIsConfigOpen(false)} 
        title={`Configurar ${configMagnitude?.name}`}
      >
        <div className="space-y-8 max-h-[70vh] overflow-y-auto pr-4 custom-scrollbar">
           <p className="text-xs font-bold text-slate-400 italic">Diligencia los parámetros de aseguramiento metrológico para esta magnitud.</p>

           <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Unidades */}
              <div className="space-y-2 group">
                <div className="flex items-center gap-2 mb-1">
                  <Ruler className="w-4 h-4 text-primary" />
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Unidades</label>
                </div>
                <textarea 
                  placeholder="ej: °C, °F, K"
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 px-5 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none min-h-[80px]"
                />
              </div>

              {/* Métodos */}
              <div className="space-y-2 group">
                <div className="flex items-center gap-2 mb-1">
                  <Settings2 className="w-4 h-4 text-primary" />
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Métodos</label>
                </div>
                <textarea 
                  placeholder="ej: Comparación directa, Puntos fijos"
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 px-5 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none min-h-[80px]"
                />
              </div>

              {/* Modelos de Incertidumbre */}
              <div className="space-y-2 group">
                <div className="flex items-center gap-2 mb-1">
                  <Activity className="w-4 h-4 text-primary" />
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Modelos de Incertidumbre</label>
                </div>
                <textarea 
                  placeholder="ej: GUM, Monte Carlo"
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 px-5 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none min-h-[80px]"
                />
              </div>

              {/* Variables */}
              <div className="space-y-2 group">
                <div className="flex items-center gap-2 mb-1">
                  <History className="w-4 h-4 text-primary" />
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Variables</label>
                </div>
                <textarea 
                  placeholder="ej: Deriva, Resolución, Repetibilidad"
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 px-5 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none min-h-[80px]"
                />
              </div>

               {/* Documentación */}
              <div className="space-y-2 group">
                <div className="flex items-center gap-2 mb-1">
                  <FileText className="w-4 h-4 text-primary" />
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Documentación</label>
                </div>
                <textarea 
                  placeholder="ej: Instructivo INS-01, Norma ISO"
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 px-5 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none min-h-[80px]"
                />
              </div>

               {/* Criterios de Aceptación */}
              <div className="space-y-2 group">
                <div className="flex items-center gap-2 mb-1">
                  <Target className="w-4 h-4 text-primary" />
                  <label className="text-[10px] font-black text-slate-800 uppercase tracking-widest">Criterios de Aceptación</label>
                </div>
                <textarea 
                  placeholder="ej: Error < MPE, Incertidumbre < 1/3 Tolerancia"
                  className="w-full bg-slate-50 border-none rounded-2xl py-3 px-5 text-sm font-bold focus:ring-2 focus:ring-primary/20 transition-all outline-none resize-none min-h-[80px]"
                />
              </div>
           </div>

           <div className="flex gap-4 pt-4">
              <Button 
                variant="outline" 
                onClick={() => setIsConfigOpen(false)}
                className="flex-1 h-12 rounded-2xl font-bold border-slate-200"
              >
                Cerrar
              </Button>
              <Button 
                onClick={() => {
                  alert('Configuración guardada localmente (Demo)');
                  setIsConfigOpen(false);
                }}
                className="flex-1 h-12 rounded-2xl font-bold bg-primary text-white shadow-lg shadow-primary/20"
              >
                Guardar Configuración
              </Button>
           </div>
        </div>
      </Modal>

      {/* DELETE MODAL */}
      <Modal 
        isOpen={isDeleteOpen} 
        onClose={() => setIsDeleteOpen(false)} 
        title="¿Eliminar Magnitud?"
      >
        <div className="space-y-8 text-center">
           <div className="w-20 h-20 bg-red-50 rounded-full flex items-center justify-center mx-auto mb-6 ring-8 ring-red-50/50">
              <AlertCircle className="w-10 h-10 text-red-500" />
           </div>
           <p className="text-sm font-bold text-slate-500 leading-relaxed px-4">
             Estas a punto de eliminar la magnitud <span className="text-slate-800 font-black">"{magnitudeToDelete?.name}"</span>. 
             Esta acción no se puede deshacer y podría afectar a los equipos vinculados.
           </p>

           <div className="flex gap-4">
              <Button 
                variant="outline" 
                onClick={() => setIsDeleteOpen(false)}
                className="flex-1 h-12 rounded-2xl font-bold border-slate-200"
              >
                No, Volver
              </Button>
              <Button 
                variant="destructive"
                disabled={isSubmitting}
                onClick={handleDelete}
                className="flex-1 h-12 rounded-2xl font-bold gap-2 bg-red-500 hover:bg-red-600 shadow-lg shadow-red-200 text-white"
              >
                {isSubmitting && <Loader2 className="w-4 h-4 animate-spin" />}
                Sí, Eliminar
              </Button>
           </div>
        </div>
      </Modal>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { 
  Plus, 
  Search, 
  AlertTriangle, 
  CheckCircle2, 
  Clock, 
  MoreVertical,
  Filter,
  Download,
  ShieldAlert,
  HelpCircle,
  Save,
  Trash2,
  ArrowRight
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Modal } from '../components/ui/Modal';
import { ncService, type NonConformity, type RootCauseFactor } from '../services/nonConformities';
import clsx from 'clsx';

const severityMap = {
  'critica': { label: 'Crítica', color: 'bg-red-100 text-red-600 border-red-200' },
  'mayor': { label: 'Mayor', color: 'bg-orange-100 text-orange-600 border-orange-200' },
  'menor': { label: 'Menor', color: 'bg-blue-100 text-blue-600 border-blue-200' },
};

const statusMap = {
  'open': { label: 'Abierta', color: 'bg-slate-100 text-slate-500 border-slate-200' },
  'analysis': { label: 'En Análisis', color: 'bg-blue-100 text-blue-600 border-blue-200' },
  'in_progress': { label: 'En Ejecución', color: 'bg-amber-100 text-amber-600 border-amber-200' },
  'closed': { label: 'Cerrada', color: 'bg-green-100 text-green-600 border-green-200' },
  'cancelled': { label: 'Cancelada', color: 'bg-red-50 text-red-400 border-red-100' },
};

export function NoConformidades() {
  const [ncs, setNcs] = useState<NonConformity[]>([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedNC, setSelectedNC] = useState<NonConformity | null>(null);
  const [isDetailOpen, setIsDetailOpen] = useState(false);
  const [activeTab, setActiveTab] = useState<'summary' | 'rca' | 'actions' | 'closure'>('summary');
  const [rcFactors, setRcFactors] = useState<RootCauseFactor[]>([]);

  // Form State for new NC
  const [newNC, setNewNC] = useState<Partial<NonConformity>>({
    title: '',
    description: '',
    source: 'internal_audit',
    severity: 'mayor',
    status: 'open',
    detection_date: new Date().toISOString().split('T')[0]
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      const data = await ncService.getAll();
      setNcs(data);
    } catch (error) {
      console.error('Error fetching NCs:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const fetchDetailData = async (id: string) => {
    try {
      const factors = await ncService.getRootCauseFactors(id);
      setRcFactors(factors);
    } catch (error) {
       console.error('Error fetching detail data:', error);
    }
  };

  const stats = useMemo(() => {
    return {
      open: ncs.filter(n => n.status === 'open' || n.status === 'analysis').length,
      inProgress: ncs.filter(n => n.status === 'in_progress').length,
      overdue: 0, // Logic for overdue actions
      closed: ncs.filter(n => n.status === 'closed').length
    };
  }, [ncs]);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await ncService.create(newNC);
      setIsModalOpen(false);
      setNewNC({ title: '', description: '', source: 'internal_audit', severity: 'mayor', status: 'open', detection_date: new Date().toISOString().split('T')[0] });
      fetchData();
    } catch (error) {
      console.error('Error creating NC:', error);
    }
  };

  const handleOpenDetail = (nc: NonConformity) => {
    setSelectedNC(nc);
    fetchDetailData(nc.id);
    setIsDetailOpen(true);
    setActiveTab('summary');
  };

  const handleAddWhy = async (whyNumber: number, factor: string) => {
    if (!selectedNC) return;
    try {
      await ncService.addRootCauseFactor({
        nc_id: selectedNC.id,
        method: '5-why',
        why_level: whyNumber,
        factor
      });
      fetchDetailData(selectedNC.id);
    } catch (error) {
      console.error('Error adding factor:', error);
    }
  };

  const filteredNcs = ncs.filter(n => 
    n.title.toLowerCase().includes(search.toLowerCase()) || 
    n.nc_code.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800 uppercase">No Conformidades (NCR)</h1>
          <p className="text-xs font-bold text-slate-400">Control de hallazgos, causa raíz y mejora continua (ISO 17025).</p>
        </div>

        <div className="flex items-center gap-4">
          <div className="relative w-64">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4 shadow-sm" />
            <input 
              type="text" 
              placeholder="Código o título..." 
              value={search}
              onChange={(e) => setSearch(e.target.value)}
              className="w-full bg-white border border-slate-200 rounded-[1.25rem] py-3.5 pl-11 pr-4 text-[11px] font-black outline-none focus:ring-4 focus:ring-primary/5 transition-all shadow-sm"
            />
          </div>
          <Button 
            onClick={() => setIsModalOpen(true)}
            className="rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 shadow-xl shadow-red-200 bg-red-500 border-none transition-all hover:scale-[1.03] active:scale-95 text-white"
          >
            <Plus className="w-5 h-5 stroke-[3px]" />
            REGISTRAR HALLAZGO
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-red-50 rounded-2xl">
                  <ShieldAlert className="w-5 h-5 text-red-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Abiertas</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.open}</span>
               <span className="text-[10px] font-black text-red-500 tracking-wide leading-none">Pendientes</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-amber-50 rounded-2xl">
                  <Clock className="w-5 h-5 text-amber-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">En Ejecución</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.inProgress}</span>
               <span className="text-[10px] font-black text-amber-500 tracking-wide leading-none">Con acciones</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-slate-100 rounded-2xl">
                  <HelpCircle className="w-5 h-5 text-slate-500" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Vencidas</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-slate-800 tracking-tighter">{stats.overdue}</span>
               <span className="text-[10px] font-black text-slate-400 tracking-wide leading-none">Urgentes</span>
            </div>
         </Card>
         <Card className="rounded-[2.5rem] border-none bg-slate-900 p-6 shadow-xl shadow-slate-200">
            <div className="flex items-center gap-4 mb-3">
               <div className="p-3.5 bg-white/10 rounded-2xl">
                  <CheckCircle2 className="w-5 h-5 text-green-400" />
               </div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">Cerradas</span>
            </div>
            <div className="flex items-baseline gap-2">
               <span className="text-3xl font-black text-white tracking-tighter">{stats.closed}</span>
               <span className="text-[10px] font-black text-green-400 tracking-wide leading-none">Eficaces</span>
            </div>
         </Card>
      </div>

      <Card className="rounded-[2.5rem] border-none shadow-[0_12px_45px_-12px_rgba(0,0,0,0.05)] bg-white overflow-hidden">
        <div className="p-8 border-b border-slate-50 flex items-center justify-between bg-slate-50/50">
           <div className="flex items-center gap-3">
              <AlertTriangle className="w-5 h-5 text-slate-800" />
              <h2 className="text-sm font-black text-slate-800 uppercase tracking-widest">Log de Hallazgos y No Conformidades</h2>
           </div>
           <button className="p-2 text-slate-400 hover:text-slate-800 transition-colors">
              <Filter className="w-5 h-5" />
           </button>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/30">
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Código</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Hallazgo</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Severidad</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Fuente</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50">Fecha Límite</th>
                <th className="py-5 px-8 text-[10px] font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 text-right">Acciones</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {loading ? (
                [1,2,3,4,5].map(i => (
                  <tr key={i} className="animate-pulse">
                    <td colSpan={6} className="py-8 px-8"><div className="h-4 bg-slate-100 rounded-full w-full"></div></td>
                  </tr>
                ))
              ) : filteredNcs.length === 0 ? (
                <tr>
                   <td colSpan={6} className="py-12 text-center text-slate-300">
                      No hay hallazgos registrados.
                   </td>
                </tr>
              ) : filteredNcs.map((nc) => (
                <tr key={nc.id} onClick={() => handleOpenDetail(nc)} className="hover:bg-slate-50/50 transition-colors group cursor-pointer">
                  <td className="py-6 px-8">
                     <span className="text-[11px] font-black text-slate-800 border-b-2 border-red-500/20">
                        {nc.nc_code}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <div className="flex flex-col">
                        <span className="text-sm font-black text-slate-800 leading-tight group-hover:text-red-500 transition-colors">{nc.title}</span>
                        <span className={clsx("text-[9px] font-black uppercase tracking-widest inline-flex items-center gap-1.5 mt-1", statusMap[nc.status as keyof typeof statusMap]?.color || 'text-slate-400')}>
                           {statusMap[nc.status as keyof typeof statusMap]?.label || nc.status}
                        </span>
                     </div>
                  </td>
                  <td className="py-6 px-8">
                     <span className={clsx("text-[9px] font-black uppercase tracking-widest px-3 py-1.5 rounded-xl border border-transparent", severityMap[nc.severity as keyof typeof severityMap]?.color)}>
                        {severityMap[nc.severity as keyof typeof severityMap]?.label || nc.severity}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">
                        {nc.source.replace('_', ' ')}
                     </span>
                  </td>
                  <td className="py-6 px-8">
                     <span className="text-[11px] font-bold text-slate-400">
                        {nc.target_close_date ? new Date(nc.target_close_date).toLocaleDateString() : 'Por definir'}
                     </span>
                  </td>
                  <td className="py-6 px-8 text-right">
                     <button className="p-2 text-slate-300 hover:text-slate-800 transition-colors">
                        <MoreVertical className="w-5 h-5" />
                     </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </Card>

      {/* Detail & Analysis Modal */}
      <Modal isOpen={isDetailOpen} onClose={() => setIsDetailOpen(false)} title={`Gestión NCR: ${selectedNC?.nc_code || ''}`}>
        {selectedNC && (
          <div className="space-y-6">
             <div className="flex gap-2 p-1 bg-slate-100 rounded-2xl">
              {(['summary', 'rca', 'actions', 'closure'] as const).map(tab => (
                <button
                  key={tab}
                  onClick={() => setActiveTab(tab)}
                  className={clsx(
                    "flex-1 py-2.5 px-4 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all",
                    activeTab === tab ? "bg-white text-slate-800 shadow-sm" : "text-slate-400 hover:text-slate-600"
                  )}
                >
                  {tab === 'summary' ? 'Resumen' : tab === 'rca' ? 'Causa Raíz' : tab === 'actions' ? 'Acciones' : 'Cierre'}
                </button>
              ))}
            </div>

            {activeTab === 'summary' && (
               <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                  <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100 space-y-4">
                     <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Descripción del Hallazgo</p>
                        <p className="text-sm font-bold text-slate-800 leading-relaxed">{selectedNC.description}</p>
                     </div>
                     <div className="grid grid-cols-2 gap-6 pt-2">
                        <div>
                           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Fuente</p>
                           <p className="text-xs font-bold text-slate-700 capitalize">{selectedNC.source.replace('_', ' ')}</p>
                        </div>
                        <div>
                           <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Detección</p>
                           <p className="text-xs font-bold text-slate-700">{new Date(selectedNC.detection_date).toLocaleDateString()}</p>
                        </div>
                     </div>
                  </div>
                  <div className="bg-blue-50/50 p-6 rounded-[2rem] border border-blue-100/50">
                     <p className="text-[10px] font-black text-blue-500 uppercase tracking-widest mb-2">Acción Inmediata (Contención)</p>
                     <p className="text-sm font-bold text-blue-700 italic">"{selectedNC.immediate_action || 'Sin acción inmediata registrada'}"</p>
                  </div>
               </div>
            )}

            {activeTab === 'rca' && (
               <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                  <div className="flex items-center justify-between mb-4">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Método: 5 Por Qués (5-Whys)</p>
                     <Button variant="outline" className="h-8 rounded-xl text-[9px] font-black border-slate-200">CAMBIAR A ISHIKAWA</Button>
                  </div>

                  <div className="space-y-4 relative before:absolute before:left-6 before:top-8 before:bottom-8 before:w-0.5 before:bg-slate-100">
                     {[1, 2, 3, 4, 5].map(i => {
                        const factor = rcFactors.find(f => f.why_level === i);
                        return (
                           <div key={i} className="relative pl-12">
                              <div className={clsx("absolute left-1 top-0 w-10 h-10 rounded-2xl flex items-center justify-center font-black text-xs ring-4 ring-white", factor ? "bg-primary text-white" : "bg-slate-100 text-slate-300")}>
                                 {i}
                              </div>
                              {factor ? (
                                 <div className="bg-white border border-slate-200 p-4 rounded-2xl shadow-sm group">
                                    <p className="text-[11px] font-bold text-slate-800">{factor.factor}</p>
                                    <button onClick={() => ncService.removeRootCauseFactor(factor.id).then(() => fetchDetailData(selectedNC.id))} className="absolute hidden group-hover:block -right-2 -top-2 p-1.5 bg-red-500 text-white rounded-lg shadow-lg">
                                       <Trash2 className="w-3 h-3" />
                                    </button>
                                 </div>
                              ) : (
                                 <div className="flex gap-2">
                                    <input 
                                       placeholder={`¿Por qué ocurrió el paso ${i}?`} 
                                       className="flex-1 bg-slate-50 border-none rounded-2xl px-4 text-xs font-bold outline-none h-10"
                                       onKeyDown={(e) => {
                                          if (e.key === 'Enter') {
                                             handleAddWhy(i, (e.target as HTMLInputElement).value);
                                             (e.target as HTMLInputElement).value = '';
                                          }
                                       }}
                                    />
                                    <Button className="h-10 w-10 p-0 rounded-2xl bg-slate-200 text-slate-400 group-hover:bg-primary group-hover:text-white">
                                       <ArrowRight className="w-4 h-4" />
                                    </Button>
                                 </div>
                              )}
                           </div>
                        );
                     })}
                  </div>

                  <div className="p-4 bg-primary/5 rounded-[2rem] border border-primary/10">
                     <p className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">Resumen Causa Raíz</p>
                     <p className="text-sm font-bold text-slate-800">{rcFactors.find(f => f.why_level === 5)?.factor || 'Análisis incompleto'}</p>
                  </div>
               </div>
            )}

            {activeTab === 'actions' && (
               <div className="space-y-4 animate-in fade-in slide-in-from-right-4 duration-300">
                  <div className="flex items-center justify-between">
                     <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Acciones Correctivas (CAPA)</p>
                     <Button className="h-9 px-4 rounded-xl text-[10px] font-black bg-primary text-white gap-2">
                        <Plus className="w-4 h-4" /> AGREGAR ACCIÓN
                     </Button>
                  </div>

                  <div className="space-y-3">
                     {selectedNC.nc_corrective_actions?.length === 0 && <p className="text-center py-8 text-[10px] font-bold text-slate-400">No hay acciones registradas.</p>}
                     {selectedNC.nc_corrective_actions?.map(action => (
                        <div key={action.id} className="bg-white border border-slate-100 p-5 rounded-[2rem] hover:shadow-md transition-all">
                           <div className="flex items-start justify-between gap-4">
                              <div className="space-y-1">
                                 <p className="text-sm font-bold text-slate-800">{action.action_description}</p>
                                 <div className="flex items-center gap-4">
                                    <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Responsable: {action.responsible}</span>
                                    <span className="text-[10px] font-black text-red-400 uppercase tracking-widest">Límite: {new Date(action.due_date).toLocaleDateString()}</span>
                                 </div>
                              </div>
                              <span className={clsx("text-[9px] font-black uppercase tracking-widest px-2 py-1 rounded-lg border", action.status === 'done' ? 'bg-green-50 text-green-500 border-green-100' : 'bg-slate-50 text-slate-400')}>
                                 {action.status}
                              </span>
                           </div>
                        </div>
                     ))}
                  </div>
               </div>
            )}

            {activeTab === 'closure' && (
               <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
                  <div className="grid grid-cols-2 gap-6">
                     <div className="bg-slate-50 p-6 rounded-[2rem] text-center">
                        <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Acciones Cerradas</p>
                        <p className="text-2xl font-black text-slate-800">
                           {selectedNC.nc_corrective_actions?.filter(a => a.status === 'done').length} / {selectedNC.nc_corrective_actions?.length}
                        </p>
                     </div>
                     <div className="bg-slate-50 p-6 rounded-[2rem] text-center">
                        <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Eficacia</p>
                        <p className="text-2xl font-black text-green-500">
                           {selectedNC.nc_corrective_actions?.length ? Math.round((selectedNC.nc_corrective_actions.filter(a => a.status === 'done').length / selectedNC.nc_corrective_actions.length) * 100) : 0}%
                        </p>
                     </div>
                  </div>

                  <div className="space-y-4 p-6 bg-red-50/30 rounded-[2.5rem] border border-red-50">
                     <p className="text-xs font-black text-slate-800 uppercase tracking-widest text-center">Cierre Definitivo</p>
                     <div className="space-y-2">
                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Evidencia Final de Cierre</label>
                        <div className="border-2 border-dashed border-red-100 rounded-[2rem] p-8 flex flex-col items-center justify-center gap-2 bg-white/50">
                           <Download className="w-6 h-6 text-red-200" />
                           <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Subir Reporte de Eficacia</span>
                        </div>
                     </div>
                     <Button 
                        disabled={selectedNC.status === 'closed' || selectedNC.nc_corrective_actions?.some(a => a.status !== 'done')} 
                        className="w-full h-14 rounded-[2rem] bg-slate-900 text-white font-black text-sm shadow-xl hover:scale-[1.02] active:scale-95 transition-all"
                     >
                        {selectedNC.status === 'closed' ? 'NCR CERRADA EXITOSAMENTE' : 'VERIFICAR Y CERRAR NCR'}
                     </Button>
                  </div>
               </div>
            )}
          </div>
        )}
      </Modal>

      {/* New NC Modal */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Registro de Hallazgo / No Conformidad">
         <form onSubmit={handleCreate} className="space-y-6">
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Título del Hallazgo</label>
               <input required placeholder="ej: Desviación en calibración de manómetro EPT-P8" className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-red-500/20 outline-none" value={newNC.title} onChange={(e) => setNewNC({...newNC, title: e.target.value})} />
            </div>

            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Descripción Detallada (Evidencia Objetiva)</label>
               <textarea rows={3} required placeholder="Describa el incumplimiento detectado..." className="w-full bg-slate-50 border-none rounded-3xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-red-500/20 outline-none resize-none" value={newNC.description} onChange={(e) => setNewNC({...newNC, description: e.target.value})} />
            </div>

            <div className="grid grid-cols-2 gap-6">
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Fuente</label>
                  <select 
                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-red-500/20 outline-none"
                    value={newNC.source}
                    onChange={(e) => setNewNC({...newNC, source: e.target.value as any})}
                  >
                    <option value="internal_audit">Auditoría Interna</option>
                    <option value="external_audit">Auditoría Externa</option>
                    <option value="client_complaint">Queja Cliente</option>
                    <option value="calibration">Proceso Calibración</option>
                    <option value="observation">Observación / Hallazgo</option>
                  </select>
               </div>
               <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Severidad</label>
                  <select 
                    className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-red-500/20 outline-none"
                    value={newNC.severity}
                    onChange={(e) => setNewNC({...newNC, severity: e.target.value as any})}
                  >
                    <option value="menor">Menor (Obs)</option>
                    <option value="mayor">Mayor (NC)</option>
                    <option value="critica">Crítica (Block)</option>
                  </select>
               </div>
            </div>

            <div className="flex gap-4 pt-4">
               <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="flex-1 h-13 rounded-2xl font-black border-slate-200 uppercase">cancelar</Button>
               <Button type="submit" className="flex-1 h-13 rounded-2xl font-black bg-red-500 text-white shadow-xl shadow-red-200 uppercase gap-3">
                 <Save className="w-5 h-5" /> guardar hallazgo
               </Button>
            </div>
         </form>
      </Modal>
    </div>
  );
}

import { useState, useEffect, useMemo } from 'react';
import { 
  Calendar as CalendarIcon, 
  ChevronLeft, 
  ChevronRight, 
  Plus, 
  Wand2, 
  Clock, 
  AlertCircle,
  FileText,
  Loader2,
  Monitor,
  Tag,
  Settings,
  Hash,
  CalendarDays
} from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Modal } from '../components/ui/Modal';
import { scheduleService, type CalibrationScheduleItem } from '../services/schedule';
import { equipmentService, type Equipment } from '../services/equipment';
import { 
  format, 
  startOfMonth, 
  endOfMonth, 
  startOfWeek, 
  endOfWeek, 
  eachDayOfInterval, 
  isSameDay, 
  addMonths, 
  subMonths,
  addDays,
  differenceInDays 
} from 'date-fns';
import { es } from 'date-fns/locale';
import clsx from 'clsx';

const getMetrologicalStatus = (e: Equipment) => {
  if (!e.last_calibration_date) return { label: 'Pendiente', color: 'bg-slate-400', text: 'text-white shadow-slate-100' };
  const next = addDays(new Date(e.last_calibration_date), e.calibration_period_days || 365);
  const diff = differenceInDays(next, new Date());
  if (diff < 0) return { label: 'Vencido', color: 'bg-red-500', text: 'text-white shadow-red-200' };
  if (diff <= 30) return { label: 'Próximo', color: 'bg-orange-400', text: 'text-white shadow-orange-200' };
  return { label: 'Vigente', color: 'bg-green-500', text: 'text-white shadow-green-200' };
};

type ViewMode = 'day' | 'week' | 'month';

export function ProgramaCalibracion() {
  const [currentDate, setCurrentDate] = useState(new Date());
  const [viewMode, setViewMode] = useState<ViewMode>('month');
  const [schedule, setSchedule] = useState<CalibrationScheduleItem[]>([]);
  const [equipmentList, setEquipmentList] = useState<Equipment[]>([]);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [loading, setLoading] = useState(true);

  // Manual Form State
  const [newManual, setNewManual] = useState({
    equipment_id: '',
    scheduled_date: format(new Date(), 'yyyy-MM-dd'),
    notes: ''
  });

  const fetchData = async () => {
    try {
      setLoading(true);
      const [sData, eData] = await Promise.all([
        scheduleService.getSchedule(),
        equipmentService.getAll()
      ]);
      setSchedule(sData);
      setEquipmentList(eData);
    } catch (error) {
      console.error('Error fetching:', error);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  const handleAutoGenerate = async () => {
    if (equipmentList.length === 0) {
      alert("No hay equipos activos con periodos de calibración configurados.");
      return;
    }

    setIsGenerating(true);
    let createdCount = 0;
    let localSchedule = [...schedule];
    try {
      for (const e of equipmentList) {
        if (e.status === 'active' && (e.calibration_period_days || 0) > 0) {
          const lastDate = e.last_calibration_date ? new Date(e.last_calibration_date) : new Date();
          const nextDate = addDays(lastDate, e.calibration_period_days);

          const isAlreadyScheduled = localSchedule.some(s => s.equipment_id === e.id && isSameDay(new Date(s.scheduled_date), nextDate));

          if (!isAlreadyScheduled) {
            const newItem = await scheduleService.createScheduleItem({
              equipment_id: e.id,
              scheduled_date: format(nextDate, 'yyyy-MM-dd'),
              type: 'automatic',
              status: 'scheduled',
              work_order_no: `WO-${(e.internal_id || 'EQ').split(' ')[0]}-${Date.now().toString().slice(-4)}`
            });
            localSchedule.push(newItem);
            createdCount++;
          }
        }
      }
      if (createdCount > 0) {
        alert(`${createdCount} nuevas órdenes de trabajo generadas correctamente.`);
        fetchData();
      } else {
        alert("No se encontraron nuevas fechas para programar.");
      }
    } catch (error) {
      console.error('Error generating:', error);
      alert('Error en generación automática. Verifica la conexión a Supabase.');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleManualSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await scheduleService.createScheduleItem({
        ...newManual,
        type: 'manual',
        status: 'scheduled',
        work_order_no: `MAN-${Date.now().toString().slice(-6)}`
      });
      setIsModalOpen(false);
      fetchData();
    } catch (error) {
      console.error('Manual error:', error);
      alert('Error al programar manualmente.');
    }
  };

  // View data calculation
  const viewDays = useMemo(() => {
    if (viewMode === 'month') {
      const start = startOfWeek(startOfMonth(currentDate), { weekStartsOn: 1 });
      const end = endOfWeek(endOfMonth(currentDate), { weekStartsOn: 1 });
      return eachDayOfInterval({ start, end });
    } else if (viewMode === 'week') {
      const start = startOfWeek(currentDate, { weekStartsOn: 1 });
      const end = endOfWeek(currentDate, { weekStartsOn: 1 });
      return eachDayOfInterval({ start, end });
    } else {
      return [currentDate];
    }
  }, [currentDate, viewMode]);

  const getEventsForDay = (date: Date) => {
    const dateStr = format(date, 'yyyy-MM-dd');
    const events: any[] = [];

    equipmentList.forEach(e => {
      // Show equipment that are active, pending calibration or even in maintenance
      // Only hide if specifically 'out_of_service'
      if (e.status !== 'out_of_service' && e.last_calibration_date && (e.calibration_period_days || 0) > 0) {

        // Use a safer date parsing (manual to avoid TZ shifts for YYYY-MM-DD strings)
        const [year, month, day] = e.last_calibration_date.split('-').map(Number);
        const lastDate = new Date(year, month - 1, day);
        const nextDate = addDays(lastDate, e.calibration_period_days);
        const nextDateStr = format(nextDate, 'yyyy-MM-dd');

        if (nextDateStr === dateStr) {
          const realEvent = schedule.find(s => s.equipment_id === e.id);

          if (realEvent) {
             events.push({
                ...realEvent,
                scheduled_date: nextDateStr,
                equipment: e
             });
          } else {
             events.push({
                id: `suggested-${e.id}`,
                equipment_id: e.id,
                scheduled_date: nextDateStr,
                status: 'suggested' as const,
                work_order_no: 'Sugerida',
                equipment: e
             });
          }
        }
      }
    });

    return events;
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-6 duration-700">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6">
        <div className="space-y-1">
          <h1 className="text-3xl font-black tracking-tight text-slate-800">Programa de Calibraciones</h1>
          <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Planificación estratégica de la trazabilidad metrológica.</p>
        </div>

        <div className="flex items-center gap-4">
          <Button 
            onClick={handleAutoGenerate}
            disabled={isGenerating}
            className={clsx(
              "rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 transition-all active:scale-95 text-white shadow-xl shadow-slate-200",
              isGenerating ? "bg-slate-300" : "bg-slate-900"
            )}
          >
            {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Wand2 className="w-5 h-5" />}
            PROGRAMACIÓN INTELIGENTE
          </Button>
          <Button 
            onClick={() => setIsModalOpen(true)}
            className="rounded-[1.25rem] h-13 px-8 font-black flex items-center gap-3 shadow-xl shadow-primary/20 bg-primary border-none transition-all hover:scale-[1.03] active:scale-95 text-white"
          >
            <Plus className="w-5 h-5 stroke-[3px]" />
            PROGRAMA MANUAL
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
         <div className="lg:col-span-3 space-y-6">
            <Card className="rounded-[2.5rem] border-none bg-white p-6 shadow-sm flex flex-col h-[calc(100vh-220px)] overflow-hidden">
               <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-6 mb-4">
                  <div className="flex items-center gap-4">
                     <div className="bg-primary/5 p-3.5 rounded-2xl text-primary border border-primary/10">
                        <CalendarIcon className="w-6 h-6" />
                     </div>
                     <div className="flex flex-col">
                        <h2 className="text-xl font-black text-slate-800 capitalize leading-tight">
                           {format(currentDate, viewMode === 'day' ? 'dd MMMM yyyy' : 'MMMM yyyy', { locale: es })}
                        </h2>
                        <span className="text-[10px] font-black text-primary uppercase tracking-widest">Vista {viewMode === 'month' ? 'Mensual' : viewMode === 'week' ? 'Semanal' : 'Diaria'}</span>
                     </div>
                  </div>

                  <div className="flex items-center gap-4">
                     <div className="flex bg-slate-50 p-1 rounded-xl border border-slate-100">
                        {(['day', 'week', 'month'] as ViewMode[]).map((mode) => (
                           <button
                             key={mode}
                             onClick={() => setViewMode(mode)}
                             className={clsx(
                                "px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all",
                                viewMode === mode ? "bg-white text-slate-800 shadow-sm border border-slate-100" : "text-slate-400 hover:text-slate-600"
                             )}
                           >
                             {mode === 'day' ? 'Día' : mode === 'week' ? 'Semana' : 'Mes'}
                           </button>
                        ))}
                     </div>

                     <div className="h-8 w-px bg-slate-100" />

                     <div className="flex items-center gap-2">
                        <button onClick={() => setCurrentDate(subMonths(currentDate, 1))} className="p-3 text-slate-400 hover:text-slate-800 hover:bg-slate-50 transition-all rounded-xl active:scale-90 border border-transparent hover:border-slate-100">
                           <ChevronLeft className="w-6 h-6" />
                        </button>
                        <button onClick={() => setCurrentDate(new Date())} className="px-4 py-2 text-[10px] font-black text-slate-800 hover:bg-slate-50 rounded-lg transition-all border border-slate-100">Hoy</button>
                        <button onClick={() => setCurrentDate(addMonths(currentDate, 1))} className="p-3 text-slate-400 hover:text-slate-800 hover:bg-slate-50 transition-all rounded-xl active:scale-90 border border-transparent hover:border-slate-100">
                           <ChevronRight className="w-6 h-6" />
                        </button>
                     </div>
                  </div>
               </div>

               {loading ? (
                 <div className="flex flex-col items-center justify-center py-40 gap-4">
                    <Loader2 className="w-12 h-12 text-primary animate-spin" />
                    <p className="text-sm font-black text-slate-400 uppercase tracking-widest">Sincronizando programa...</p>
                 </div>
               ) : (
                 <div className={clsx(
                    "grid gap-2 h-full overflow-y-auto pr-1 flex-1 custom-scrollbar",
                    viewMode === 'month' ? "grid-cols-7" : viewMode === 'week' ? "grid-cols-7" : "grid-cols-1"
                 )}>
                    {viewMode !== 'day' && (['Lun', 'Mar', 'Mié', 'Jue', 'Vie', 'Sáb', 'Dom']).map(d => (
                      <div key={d} className="text-center text-[9px] font-black text-slate-300 uppercase tracking-widest pb-2">{d}</div>
                    ))}

                    {viewDays.map((date, i) => {
                      const events = getEventsForDay(date);
                      const isToday = isSameDay(date, new Date());
                      const isOtherMonth = viewMode === 'month' && format(date, 'MM') !== format(currentDate, 'MM');

                      return (
                        <div 
                          key={i} 
                          className={clsx(
                            "min-h-[90px] rounded-[1.5rem] p-3 border transition-all flex flex-col gap-1.5 relative group",
                            isToday ? "ring-1 ring-primary bg-white shadow-xl shadow-primary/5" : "bg-white border-slate-50 hover:border-primary/20",
                            isOtherMonth && "opacity-30",
                            viewMode === 'day' && "max-w-2xl mx-auto w-full min-h-[400px] p-8"
                          )}
                        >
                           <div className="flex items-center justify-between mb-1">
                              <span className={clsx("text-base font-black transition-colors", 
                                 isToday ? "text-primary" : isOtherMonth ? "text-slate-200" : "text-slate-300 group-hover:text-slate-800")
                              }>
                                {format(date, 'd')}
                              </span>
                           </div>

                           <div className="space-y-1.5 mt-1 overflow-hidden">
                              {events.map((e) => {
                                const metStatus = e.equipment ? getMetrologicalStatus(e.equipment) : { color: 'bg-slate-200', text: 'text-slate-600' };
                                return (
                                  <Card 
                                    key={e.id}
                                    onClick={(event) => {
                                       event.stopPropagation();
                                       setSelectedEvent(e);
                                       setIsDetailModalOpen(true);
                                    }}
                                    className={clsx(
                                       "p-1.5 rounded-xl border-none flex items-center justify-center transition-all active:scale-95 cursor-pointer shadow-lg group/event", 
                                       metStatus.color,
                                       metStatus.text,
                                       e.status === 'suggested' && "opacity-80 border-2 border-dashed border-white/30"
                                    )}
                                  >
                                     <div className="flex flex-col min-w-0 flex-1 text-center">
                                        <span className="text-[10px] font-black uppercase truncate leading-tight tracking-widest drop-shadow-sm">
                                           {e.equipment?.internal_id || 'S/N'}
                                        </span>
                                     </div>
                                  </Card>
                                );
                              })}
                           </div>
                        </div>
                      );
                    })}
                 </div>
               )}
            </Card>
         </div>

          <div className="lg:col-span-1 flex flex-col gap-6 h-[calc(100vh-220px)] overflow-hidden">
             <Card className="p-6 rounded-[2rem] border-none bg-white shadow-sm flex-1 flex flex-col justify-center">
               <h3 className="text-xs font-black text-slate-800 uppercase tracking-widest mb-4 flex items-center gap-3">
                  <Clock className="w-5 h-5 text-orange-500" />
                  Estado del Mes
               </h3>
               <div className="space-y-3">
                  <div className="p-3 rounded-2xl flex items-center justify-between bg-slate-50 border border-slate-100">
                     <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Programadas</span>
                     <span className="text-xl font-black text-slate-800">{schedule.length}</span>
                  </div>
                  <div className="p-3 rounded-2xl flex items-center justify-between bg-green-50 border border-green-100">
                     <span className="text-[10px] font-black text-green-600 uppercase tracking-widest">Completadas</span>
                     <span className="text-xl font-black text-green-600">0</span>
                  </div>
                  <div className="p-3 rounded-2xl flex items-center justify-between bg-red-50 border border-red-100">
                     <span className="text-[10px] font-black text-red-600 uppercase tracking-widest">Vencidas</span>
                     <span className="text-xl font-black text-red-600">0</span>
                  </div>
               </div>
            </Card>

            <Card className="rounded-[2rem] bg-slate-900 shadow-xl p-6 shadow-slate-200 flex-1 flex flex-col overflow-hidden">
                <h3 className="text-xs font-black text-white uppercase tracking-widest mb-4 flex items-center gap-3">
                   <AlertCircle className="w-5 h-5 text-orange-400" />
                   Próximas Tareas
                </h3>
                <div className="space-y-3 flex-1 overflow-y-auto pr-2 custom-scrollbar">
                  {schedule.slice(0, 5).map(e => (
                    <div key={e.id} className="bg-white/10 p-2.5 rounded-xl border border-white/5 hover:bg-white/10 transition-all group">
                       <div className="flex items-start gap-3">
                          <div className="bg-primary/20 p-2 rounded-xl">
                             <FileText className="w-4 h-4 text-primary" />
                          </div>
                          <div className="flex-1 min-w-0">
                             <p className="text-[11px] font-black text-white leading-tight truncate">{e.work_order_no}</p>
                             <p className="text-[9px] font-bold text-slate-400 truncate mt-0.5">{e.equipment?.name}</p>
                          </div>
                       </div>
                    </div>
                  ))}
                  {schedule.length === 0 && <p className="text-[10px] font-bold text-slate-500 text-center py-8">No hay órdenes para este mes.</p>}
               </div>
               <Button className="w-full mt-4 h-10 rounded-xl font-black text-[9px] bg-white text-slate-900 border-none hover:bg-slate-50 transition-all">VER TODAS</Button>
            </Card>
         </div>
      </div>

      {/* MANUAL MODAL */}
      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="Programación Manual">
         <form onSubmit={handleManualSubmit} className="space-y-6">
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Seleccionar Equipo</label>
               <select 
                 required 
                 className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none appearance-none"
                 value={newManual.equipment_id}
                 onChange={(e) => setNewManual({...newManual, equipment_id: e.target.value})}
               >
                 <option value="">Seleccione instrumento...</option>
                 {equipmentList.map(e => (
                   <option key={e.id} value={e.id}>{e.internal_id} - {e.name}</option>
                 ))}
               </select>
            </div>
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Fecha de Calibración</label>
               <input 
                 type="date" 
                 required 
                 className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none"
                 value={newManual.scheduled_date}
                 onChange={(e) => setNewManual({...newManual, scheduled_date: e.target.value})}
               />
            </div>
            <div className="space-y-2">
               <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest pl-1">Notas / Observaciones</label>
               <textarea 
                 className="w-full bg-slate-50 border-none rounded-2xl py-4 px-6 text-sm font-bold focus:ring-2 focus:ring-primary/20 outline-none min-h-[100px]"
                 value={newManual.notes}
                 onChange={(e) => setNewManual({...newManual, notes: e.target.value})}
               />
            </div>
            <div className="flex gap-4 pt-4">
               <Button type="button" variant="outline" onClick={() => setIsModalOpen(false)} className="flex-1 h-13 rounded-2xl font-black border-slate-200">CANCELAR</Button>
               <Button type="submit" className="flex-1 h-13 rounded-2xl font-black bg-primary text-white shadow-xl shadow-primary/20">CONFIRMAR FECHA</Button>
            </div>
         </form>
      </Modal>

      {/* EQUIPMENT DETAIL MODAL */}
      <Modal isOpen={isDetailModalOpen} onClose={() => setIsDetailModalOpen(false)} title="Detalles del Instrumento">
         {selectedEvent && selectedEvent.equipment && (
            <div className="space-y-8">
               <div className="flex items-center gap-6 p-6 bg-slate-50 rounded-[2rem] border border-slate-100">
                  <div className="w-20 h-20 bg-white rounded-3xl flex items-center justify-center shadow-sm">
                     {selectedEvent.equipment.image_url ? (
                        <img src={selectedEvent.equipment.image_url} alt="" className="w-16 h-16 object-contain" />
                     ) : (
                        <Monitor className="w-10 h-10 text-slate-200" />
                     )}
                  </div>
                  <div className="flex-1">
                     <h3 className="text-xl font-black text-slate-800 leading-tight">{selectedEvent.equipment.name}</h3>
                     <div className="flex items-center gap-2 mt-1">
                        <span className="text-[10px] font-black text-primary uppercase tracking-widest">{selectedEvent.equipment.magnitude?.name}</span>
                        <div className="w-1 h-1 rounded-full bg-slate-300" />
                        <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">{selectedEvent.equipment.internal_id}</span>
                     </div>
                  </div>
               </div>

               <div className="grid grid-cols-2 gap-4">
                  <div className="p-5 bg-white border border-slate-100 rounded-3xl space-y-1">
                     <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest flex items-center gap-2">
                        <Tag className="w-3 h-3" /> Marca
                     </span>
                     <p className="text-sm font-bold text-slate-700">{selectedEvent.equipment.brand || '---'}</p>
                  </div>
                  <div className="p-5 bg-white border border-slate-100 rounded-3xl space-y-1">
                     <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest flex items-center gap-2">
                        <Settings className="w-3 h-3" /> Modelo
                     </span>
                     <p className="text-sm font-bold text-slate-700">{selectedEvent.equipment.model || '---'}</p>
                  </div>
                  <div className="p-5 bg-white border border-slate-100 rounded-3xl space-y-1">
                     <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest flex items-center gap-2">
                        <Hash className="w-3 h-3" /> Serie
                     </span>
                     <p className="text-sm font-bold text-slate-700">{selectedEvent.equipment.serial_number || '---'}</p>
                  </div>
                  <div className="p-5 bg-white border border-slate-100 rounded-3xl space-y-1">
                     <span className="text-[9px] font-black text-slate-300 uppercase tracking-widest flex items-center gap-2">
                        <CalendarDays className="w-3 h-3" /> Próxima Cal.
                     </span>
                     <p className="text-sm font-black text-slate-900">{format(new Date(selectedEvent.scheduled_date), "dd 'de' MMMM", { locale: es })}</p>
                  </div>
               </div>

               <div className="p-6 rounded-[2rem] border border-primary/20 bg-primary/5 flex items-center justify-between">
                  {(() => {
                     const status = getMetrologicalStatus(selectedEvent.equipment);
                     return (
                        <>
                           <div className="flex flex-col">
                              <span className="text-[10px] font-black text-primary uppercase tracking-widest mb-1">Estado Metrológico</span>
                              <span className="text-lg font-black text-slate-800 uppercase">{status.label}</span>
                           </div>
                           <div className={clsx("px-5 py-2 rounded-2xl text-[10px] font-black text-white uppercase tracking-widest shadow-lg", status.color)}>
                              ACTIVO
                           </div>
                        </>
                     );
                  })()}
               </div>

               <div className="flex gap-4">
                  <Button variant="outline" onClick={() => setIsDetailModalOpen(false)} className="flex-1 h-14 rounded-2xl font-black text-[10px] uppercase tracking-widest">CERRAR</Button>
                  <Button className="flex-1 h-14 rounded-2xl font-black text-[10px] uppercase tracking-widest bg-slate-900 text-white shadow-xl">VER EXPEDIENTE</Button>
               </div>
            </div>
         )}
      </Modal>
    </div>
  );
}

import { supabase } from '../lib/supabase';

export interface Document {
  id: string;
  name: string;
  code: string;
  version: string;
  type: string;
  status: 'draft' | 'under_review' | 'approved' | 'archived' | 'expired';
  file_url: string | null;
  approval_date: string | null;
  expiry_date: string | null;
  reviewer_name: string | null;
  approver_name: string | null;
  revision_notes: string | null;
  created_at: string;
}

export interface DocumentVersion {
  id: string;
  document_id: string;
  version: string;
  status: string;
  file_url: string | null;
  revision_notes: string | null;
  changed_by: string;
  created_at: string;
}

export interface DocumentApproval {
  id: string;
  document_id: string;
  step: 'review' | 'approval';
  assigned_to: string;
  status: 'pending' | 'approved' | 'rejected';
  comments: string | null;
  action_date: string | null;
  created_at: string;
}

export const documentService = {
  async getDocuments() {
    const { data, error } = await supabase
      .from('documents')
      .select('*')
      .order('code', { ascending: true });

    if (error) throw error;
    return data as Document[];
  },

  async createDocument(doc: Partial<Document>) {
    const { data, error } = await supabase
      .from('documents')
      .insert([doc])
      .select()
      .single();

    if (error) throw error;
    return data as Document;
  },

  async updateDocument(id: string, updates: Partial<Document>) {
    const { data, error } = await supabase
      .from('documents')
      .update(updates)
      .eq('id', id)
      .select()
      .single();

    if (error) throw error;
    return data as Document;
  },

  async deleteDocument(id: string) {
    const { error } = await supabase
      .from('documents')
      .delete()
      .eq('id', id);

    if (error) throw error;
  },

  async getVersionHistory(documentId: string) {
    const { data, error } = await supabase
      .from('document_versions')
      .select('*')
      .eq('document_id', documentId)
      .order('created_at', { ascending: false });

    if (error) throw error;
    return data as DocumentVersion[];
  },

  async createVersionSnapshot(doc: Document) {
    const { error } = await supabase
      .from('document_versions')
      .insert([{
        document_id: doc.id,
        version: doc.version,
        status: doc.status,
        file_url: doc.file_url,
        revision_notes: doc.revision_notes,
        changed_by: doc.approver_name || 'System'
      }]);

    if (error) throw error;
  },

  async getApprovals(documentId: string) {
    const { data, error } = await supabase
      .from('document_approvals')
      .select('*')
      .eq('document_id', documentId)
      .order('created_at', { ascending: true });

    if (error) throw error;
    return data as DocumentApproval[];
  },

  async requestApproval(documentId: string, assignedTo: string, step: 'review' | 'approval') {
    const { error } = await supabase
      .from('document_approvals')
      .insert([{
        document_id: documentId,
        step,
        assigned_to: assignedTo,
        status: 'pending'
      }]);

    if (error) throw error;

    await this.updateDocument(documentId, { 
       status: step === 'review' ? 'under_review' : 'under_review',
       [step === 'review' ? 'reviewer_name' : 'approver_name']: assignedTo
    });
  },

  async approveDocument(doc: Document, role: 'reviewer' | 'approver', comments: string) {
    const isFinal = role === 'approver';
    const nextStatus = isFinal ? 'approved' : 'under_review'; // Simple flow: review -> approval -> approved

    // Update document
    const updatedDoc = await this.updateDocument(doc.id, {
      status: nextStatus as any,
      approval_date: isFinal ? new Date().toISOString() : doc.approval_date,
      revision_notes: comments
    });

    // Create history snapshot if final
    if (isFinal) {
      await this.createVersionSnapshot(updatedDoc);
    }

    // Record approval step (simple logic for now)
    const { data: currentApps } = await supabase.from('document_approvals').select('id').eq('document_id', doc.id).eq('status', 'pending').limit(1);
    if (currentApps?.[0]) {
      await supabase.from('document_approvals').update({
        status: 'approved',
        comments,
        action_date: new Date().toISOString()
      }).eq('id', currentApps[0].id);
    }

    if (!isFinal && role === 'reviewer') {
       // Request next step (Aprobación Calidad)
       await this.requestApproval(doc.id, 'Gerente de Calidad', 'approval');
    }
  },

  async rejectDocument(documentId: string, comments: string) {
    await this.updateDocument(documentId, { status: 'draft' });

    const { data: currentApps } = await supabase.from('document_approvals').select('id').eq('document_id', documentId).eq('status', 'pending').limit(1);
    if (currentApps?.[0]) {
      await supabase.from('document_approvals').update({
        status: 'rejected',
        comments,
        action_date: new Date().toISOString()
      }).eq('id', currentApps[0].id);
    }
  },

  async uploadFile(file: File) {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Math.random().toString(36).substring(2, 15)}.${fileExt}`;
    const filePath = `documents/${fileName}`;

    const { error: uploadError } = await supabase.storage
      .from('managemet_assets')
      .upload(filePath, file);

    if (uploadError) throw uploadError;

    const { data } = supabase.storage
      .from('managemet_assets')
      .getPublicUrl(filePath);

    return data.publicUrl;
  }
};
